INSERT INTO `mpx_fund_dictionary` (`fd_id`, `title`, `description`, `status`, `created_id`, `updated_id`, `created_at`, `updated_at`, `migration_at`) VALUES
(1, 'Absolute Advantage', 'An advantage a country has because it can produce a particular type of product more cheaply than another country.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(2, 'Accounting Equation', 'A mathematical statement showing that to calculate a company owners equity you subtract its liabilities from its assets.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(3, 'Accounting Rate Of Return (ARR)', 'The amount of money you invest in a project divided by the amount of profit you expect to get from it.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(4, 'Acid-Test Ratio', 'The acid-test ratio uses a firms balance sheet data as an indicator of whether it has sufficient short-term assets to cover its short-term liabilities.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(5, 'Acquisition', 'An acquisition is when one company purchases most or all of another companys shares to gain control of that company.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(6, 'Addendums and Notices', 'Offer document of a mutual fund scheme spells out all the details including investment objective risk factors sponsors track record educational qualification and work experience of key personnel.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(7, 'Adjusted Gross Income (AGI)', 'Adjusted gross income (AGI) is a measure of income calculated from your gross income and used to determine how much of your income is taxable.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(8, 'Adjusted Present Value (APV)', 'The adjusted present value is the net present value (NPV) of a project or company if financed solely by equity plus the present value (PV) of any financing benefits which are the additional effects of debt.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(9, 'Adverse Selection', 'Adverse selection refers generally to a situation in which sellers have information that buyers do not have or vice versa about some aspect of product quality?in other words it is a case where asymmetric information is exploited.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(10, 'Affiliate Marketing', 'Affiliate marketing is an advertising model in which a company compensates third-party publishers to generate traffic or leads to the company?s products and services.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(11, 'After-Tax Income', 'After-tax income is the net income after the deduction of all federal state and withholding taxes.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(12, 'After-Tax Real Rate of Return', 'The after-tax real rate of return is the actual financial benefit of an investment after accounting for the effects of inflation and taxes', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(13, 'Agency Bond', 'An agency bond is a security issued by a government-sponsored enterprise or by a federal government department other than the U.S Treasury.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(14, 'Agency Costs', 'An agency cost is a type of internal company expense which comes from the actions of an agent acting on behalf of a principal.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(15, 'Agency Theory', 'Agency theory is a principle that is used to explain and resolve issues in the relationship between business principals and their agents.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(16, 'Aggregate Demand', 'Aggregate demand is an economic measurement of the total amount of demand for all finished goods and services produced in an economy. Aggregate demand is expressed as the total amount of money exchanged for those goods and services at a specific price level and point in time.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(17, 'Aggregate Supply', 'Also known as total output is the total supply of goods and services produced within an economy at a given overall price in a given period.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(18, 'Agribusiness', 'Agribusiness is the business sector encompassing farming and farming-related commercial activities.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(19, 'Air Waybill (AWB)', 'An air waybill (AWB) is a document that accompanies goods shipped by an international air courier to provide detailed information about the shipment and allow it to be tracked.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(20, 'Allocated Loss Adjustment Expenses (ALAE)', 'Allocated loss adjustment expenses (ALAE) are attributed to the processing of a specific insurance claim. ALAE is part of an insurer?s expense reserves.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(21, 'Allowance for Bad Debt', 'An allowance for bad debt is a valuation account used to estimate the amount of a firms receivables that may ultimately be uncollectible. It is also known as an allowance for doubtful accounts.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(22, 'Allowance For Credit Losses', 'Allowance for credit losses is an estimate of the debt that a company is unlikely to recover.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(23, 'Alphabet Stock', 'An alphabet stock refers to a separate class of common stock that is tied to a specific subsidiary of a corporation.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(24, 'Alternative Depreciation System (ADS)', 'Alternative depreciation system is a depreciation schedule with a longer recovery period that generally better mirrors the assets income streams than declining balance depreciation.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(25, 'Alternative Trading System (ATS)', 'An alternative trading system (ATS) is one that is not regulated as an exchange but is a venue to match the buy and sell orders of its subscribers.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(26, 'Amended Return1', 'An amended return is a form filed in order to make corrections to a tax return from a previous year.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(27, 'Angel Investor', 'An angel investor (also known as a private investor seed investor or angel funder) is a high net worth individual who provides financial backing for small startups or entrepreneurs typically in exchange for ownership equity in the company.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(28, 'Annual Equivalent Rate (AER)', 'The AER is the interest rate for a savings account or investment product that has more than one compounding period.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(29, 'Annual General Meeting (AGM)', 'An annual general meeting (AGM) is a mandatory yearly gathering of a companys interested shareholders.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(30, 'Annual Percentage Rate (APR)', 'An annual percentage rate (APR) is the annual rate charged for borrowing or earned through an investment.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(31, 'Annual Percentage Yield (APY)', 'The annual percentage yield (APY) is the real rate of return earned on a savings deposit or investment taking into account the effect of compounding interest ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(32, 'Annualized Rate of Return', 'An annualized rate of return is calculated as the equivalent annual return an investor receives over a given period. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(33, 'Application Amount for Fresh Subscription', 'This is the minimum investment amount for a new investor in a mutual fund scheme. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(34, 'Application Programming Interface (API)', 'An application programming interface, or API, is a set of programming code that queries data, parses responses, and sends instructions between one software platform and another. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(35, 'Applied Economics', 'Applied economics applies the conclusions drawn from economic theories and empirical studies to realworld situations with the desired aim of informing economic decisions and predicting possible outcomes. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(36, 'Appreciation', 'Appreciation, in general terms, is an increase in the value of an asset over time ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(37, 'Arbitrage', 'Arbitrage is the purchase and sale of an asset in order to profit from a difference in the assets price between markets. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(38, 'Asian Financial Crisis', 'The Asian financial crisis, also called the Asian Contagion, was a sequence of currency devaluations and other events that began in the summer of 1997 and spread through many Asian markets. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(39, 'Asian Infrastructure Investment Bank (AIIB)', 'The Asian Infrastructure Investment Bank (AIIB) is a new international development bank that provides financing for infrastructure projects in Asia. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(40, 'Asset allocation', ' The process of dividing investments among cash, income and growth buckets to optimize the balance between risk and reward based on investment needs.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(41, 'Asset class', 'Securities with similar features. The most common asset classes are stocks, bonds and cash equivalents. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(42, 'Asset Management', 'Asset management is the direction of all or part of a clients portfolio by a financial services institution, usually an investment bank, or an individual. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(43, 'Asset Management Company (AMC)', 'Asset Management Company is the company that manages funds of individuals. A mutual fund is a trust registered under the Indian Trust Act. It is initiated by a sponsor. A sponsor is a person who acts alone or with a corporate to establish a mutual fund. The sponsor then appoints an AMC to manage the investment, marketing, accounting and other functions pertaining to the fund. Various funds can be introduced by a single AMC according to investment objective. It is a pool where funds are collected and invested professionally and the returns are distributed proportionally. In India all AMCs are required to get themselves registered with SEBI before starting its operations. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(44, 'Asset Turnover Ratio', 'The asset turnover ratio measures the value of a companys sales or revenues relative to the value of its assets. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(45, 'Asset-Backed Commercial Paper (ABCP)', ' An asset backed commercial paper (ABCP) is a short term investment vehicle with a maturity that is typically between 90 and 270 days.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(46, 'Asset-Backed Security (ABS)', ' An assetbacked security (ABS) is a financial security such as a bond or note which is collateralized by a pool of assets such as loans, leases, credit card debt, royalties, or receivables.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(47, 'Assets Under Management (AUM)', 'AUM or assets under management refers to the recent  updated cumulative market value of investments managed by a mutual fund or any investment firm. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(48, 'Auction Market', 'In an auction market, buyers enter competitive bids and sellers submit competitive offers at the same time. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(49, 'Audit', 'A financial audit is an objective examination and evaluation of the financial statements of an organization to make sure that the financial records are a fair and accurate representation of the transactions they claim to represent. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(50, 'Average Annual Growth Rate (AAGR)', 'The average annual growth rate (AAGR) is the average increase in the value of an individual investment, portfolio, asset, or cash stream over the period of a year ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(51, 'Average Daily Rate (ADR)', 'The average daily rate (ADR) is a metric widely used in the hospitality industry to indicate the average revenue earned for an occupied room on a given day. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(52, 'Average maturity', 'For a bond fund, the average of the stated maturity dates of the debt securities in the portfolio. Also called average weighted maturity. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(53, 'Balance Maturity Tenure Of A Scheme', 'It is used in closeended schemes and is referred to as the balance term remaining until the redemption of the scheme. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(54, 'Balance Sheet', 'An accounting statement of a companys assets and liabilities, provided for the benefit of shareholders and regulators. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(55, 'Balanced Budget', ' A balanced budget is a situation in financial planning or the budgeting process where total revenues are equal to or greater than total expenses.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(56, 'Balanced Fund', 'Mutual funds that seek both growth and income in a portfolio with a mix of common stock, preferred stock or bonds. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(57, 'Balanced Funds', 'Funds which aim to provide both growth and regular income as such schemes invest both in equities and fixed income securities in the proportion indicated in their offer documents. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(58, 'Bank Capital', 'Bank capital is the difference between a banks assets and its liabilities, and it represents the net worth of the bank or its equity value to investors. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(59, 'Bank Reconciliation Statement', 'A bank reconciliation statement is a summary of banking and business activity that reconciles an entitys bank account with its financial records. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(60, 'Bank Reserves', 'Bank reserves are the cash minimums that must be kept on hand by financial institutions in order to meet central bank requirements. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(61, 'Basis Point', 'One hundredth of a percentage point. Basis points are used in currency and bond markets where the size of trades mean that large amounts of money can change hands on small price movements . ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(62, 'Basis Points (BPS)', 'Basis points (BPS) refers to a common unit of measure for interest rates and other percentages in finance. One basis point is equal to 1100th of 1, or 0.01, or 0.0001, ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(63, 'BAT Stocks', 'BAT is an acronym referring to Baidu Inc. (BIDU), Alibaba Group Holding Ltd. (BABA) and Tencent Holdings Ltd. (0700.Hong Kong, TCEHY), three large Chinese internet stocks often likened to Alphabet Inc. (GOOG) subsidiary Google, Amazon.com Inc. (AMZN) and Facebook Inc. (FB). The BATs are often compared to the FANGsor variationswhich comprise Facebook, Amazon, Netflix Inc. (NFLX) and Alphabet. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(64, 'Bear market', 'A bear market is a prolonged period of falling stock prices, usually marked by a decline of 20 or more. A market in which prices decline sharply against a background of widespread pessimism, growing unemployment or business recession. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(65, 'Behavioral Finance', ' Behavioral finance, a subfield of behavioral economics, proposes that psychological influences and biases affect the financial behaviors of investors and financial practitioners.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(66, 'Benchmark', 'A benchmark is a standard against which the performance of a security, mutual fund or investment manager can be measured. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(67, 'Benchmark Index', ' In mutual fund parlance, very often we hear that a particular scheme has outperformed or underperformed its benchmark index.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(68, 'Benefit-Cost Ratio (BCR)', 'A benefitcost ratio (BCR) is a ratio used in a costbenefit analysis to summarize the overall relationship between the relative costs and benefits of a proposed project. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(69, 'Beta', 'Beta is a measure of an investments volatility visavis the market. Beta of less than 1 means that the security will be less volatile than the market. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(70, 'Bid', 'A bid is an offer made by an investor, trader, or dealer in an effort to buy a security, commodity, or currency. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(71, 'Bid Bond', 'A bid bond guarantees compensation to the bond owner if the bidder fails to begin a project. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(72, 'Bid Price', ' A bid price is a price which is offered for a commodity, service, or contract. It is colloquially known as a bid in many markets and jurisdictions.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(73, 'Bitcoin', ' Bitcoin is a digital currency created in January 2009.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(74, 'Blue Chip', 'A blue chip is a nationally recognized, wellestablished, and financially sound company. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(75, 'Blue-Chip Stocks', ' The best rated shares with the highest status as investment based on return, yield, safety, marketability and liquidity', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(76, 'Board of Trustees', 'A governing board elected or appointed to direct the policies of an institution. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(77, 'Bombay Stock Exchange (BSE)', 'The Bombay Stock Exchange (BSE) is the first and largest securities market in India and was established in 1875 as the Native Share and Stock Brokers Association. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(78, 'Bond', 'A bond acts like a loan or an IOU that is issued by a corporation, municipality or the U.S. governmen. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(79, 'Bond Fund', 'A bond fund, also referred to as a debt fund, invests primarily in bonds (government, municipal, corporate, convertible) and other debt instruments, like mortgagebacked securities (MBS), with the primary goal of generating monthly income for investors. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(80, 'Bond Market', 'The bond marketoften called the debt market, fixedincome market, or credit marketis the collective name given to all trades and issues of debt securities. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(81, 'Book Value Per Common Share - BVPS', ' Book value per common share (or, simply book value per share  BVPS) is a method to calculate the pershare value of a company based on common shareholders equity in the company.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(82, 'Book Value Per Share ГўвӮ¬вҖң BVPS', 'Book value of equity per share (BVPS) is the ratio of equity available to common shareholders divided by the number of outstanding shares. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(83, 'Book-To-Market Ratio', 'The booktomarket ratio is used to find a companys value by comparing its book value to its market value. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(84, 'Breakeven Point (BEP)', 'In accounting, the breakeven point formula is determined by dividing the total fixed costs associated with production by the revenue per individual unit minus the variable costs per unit. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(85, 'Break-Even Price', ' Breakeven price is the amount of money, or change in value, for which an asset must be sold to cover the costs of acquiring and owning it.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(86, 'Breakout', 'A breakout refers to when the price of an asset moves above a resistance area, or moves below a support area. Breakouts indicate the potential for the price to start trending in the breakout direction. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(87, 'Bridge Financing', 'Bridge financing, often in the form of a bridge loan, is an interim financing option used by companies and other entities to solidify their shortterm position until a longterm financing option can be arranged. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(88, 'Broker', ' A broker is an individual or firm that acts as an intermediary between an investor and a securities exchange.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(89, 'Brokerage Fee', 'A brokerage fee is a fee charged by a broker to execute transactions or provide specialized services. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(90, 'Bull Market', ' A bull market is the condition of a financial market in which prices are rising or are expected to rise.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(91, 'Bullet Bond', 'A bullet bond is a debt instrument whose entire principal value is paid all at once on the maturity date, as opposed to amortizing the bond over its lifetime. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(92, 'Bureaucracy', 'A bureaucracy typically refers to an organization that is complex with multilayered systems and processes. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(93, 'Business Cycle', 'The business cycle describes the rise and fall in production output of goods and services in an economy. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(94, 'Business Development Company (BDC)', 'A business development company (BDC) is an organization that invests in small and mediumsized companies as well as distressed companies. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(95, 'Business Economics', 'Business economics is a field of applied economics that studies the financial, organizational, marketrelated, and environmental issues faced by corporations. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(96, 'Butterfly Spread Option', ' Also called butterfly option, is a neutral option strategy that has limited risk.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(97, 'Buy To Open', 'Buy to open is a term used by brokerages to represent the establishment of a new (opening) long call or put position in options. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(98, 'Buyback', 'A buyback, also known as a share repurchase, is when a company buys its own outstanding shares to reduce the number of shares available on the open market. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(99, 'Buy-Side', 'The financial institutions of Wall Street include a segment called the buyside. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(100, 'Cap and Trade', ' Cap and trade is a common term for a government regulatory program designed to limit, or cap, the total level of emissions of certain chemicals, particularly carbon dioxide, as a result of industrial activity.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(101, 'CAPE Ratio', ' The CAPE ratio is a valuation measure that uses real earnings per share (EPS) over a 10year period to smooth out fluctuations in corporate profits that occur over different periods of a business cycle. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(102, 'Capital', ' Capital is a term for financial assets, such as funds held in deposit accounts andor funds obtained from special financing sources.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(103, 'Capital Asset', 'Capital assets are significant pieces of property such as homes, cars, investment properties, stocks, bonds, and even collectibles or art. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(104, 'Capital Asset Pricing Model (CAPM)', 'The Capital Asset Pricing Model (CAPM) describes the relationship between systematic risk and expected return for assets, particularly stocks. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(105, 'Capital Gain', 'Capital gain is a rise in the value of a capital asset (investment or real estate) that gives it a higher worth than the purchase price. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(106, 'Capital gains ex-date', ' The Capital Asset Pricing Model (CAPM) describes the relationship between systematic risk and expected return for assets, particularly stocks.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(107, 'Capital gains long term', 'The difference between an assets purchase price and selling price (when the difference is positive) that was earned in more than one year. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(108, 'Capital gains reinvest NAV', 'The difference between an assets purchase price and selling price (when the difference is positive) that was automatically in vested in more shares of the security or mutual fund invested at the securitys net asset value. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(109, 'Capital gains short term', 'The difference between an assets purchase price and selling price (when the difference is positive) that was earned in under one year. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(110, 'Capital Investment', 'Capital investment is a sum of money provided to a company to further its business objectives. The term also can refer to a companys acquisition of longterm assets such as real estate, manufacturing plants, and machinery. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(111, 'Capital loss', 'The amount by which the proceeds from a sale of a security are less than its purchase price. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(112, 'Capital Market Line (CML)', 'The capital market line (CML) represents portfolios that optimally combine risk and return. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(113, 'Capital Markets', 'Capital markets are venues where savings and investments are channeled between the suppliers who have capital and those who are in need of capital. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(114, 'Capitalization', 'In finance, capitalization refers to the cost of capital in the form of a corporations stock, longterm debt, and retained earnings. In addition, market capitalization refers to the number of outstanding shares multiplied by the share price. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(115, 'Capitalization Rate', ' The capitalization rate (also known as cap rate) is used in the world of commercial real estate to indicate the rate of return that is expected to be generated on a real estate investment property. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(116, 'Cash Cow', ' A cash cow is one of the four categories (quadrants) in the growthshare, BCG matrix that represents a product, product line, or company with a large market share within a mature industry.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(117, 'Cash Dividend', 'A cash dividend is funds or money paid to stockholders generally as part of the corporations current earnings or accumulated profits. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(118, 'Cash Equivalents', ' Cash equivalents are investments securities that are meant for shortterm investing they have high credit quality and are highly liquid.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(119, 'Cash Flow From Financing Activities ГўвӮ¬вҖң CFF', 'Cash flow from financing activities (CFF) is a section of a companys cash flow statement, which shows the net flows of cash that are used to fund the company. Financing activities include transactions involving debt, equity, and dividends. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(120, 'Cash Flow from Investing Activities', 'Cash flow from investing activities is one of the sections on the cash flow statement that reports how much cash has been generated or spent from various investmentrelated activities in a specific period. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(121, 'Cash Ratio', 'The cash ratio is a measurement of a companys liquidity, specifically the ratio of a companys total cash and cash equivalents to its current liabilities. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(122, 'Certificate of Deposit (CD)', ' A certificate of deposit (CD) is a product offered by banks and credit unions that provides an interest rate premium in exchange for the customer agreeing to leave a lumpsum deposit untouched for a predetermined period of time', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(123, 'Circular Flow Model', 'The circular flow model demonstrates how money moves through society. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(124, 'Clawback', 'A clawback is a contractual provision whereby money already paid to an employee must be returned to an employer or benefactor, sometimes with a penalty. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(125, 'Closed-End Fund', ' A closedend fund is a portfolio of pooled assets that raises a fixed amount of capital through an initial public offering (IPO) and then lists shares for trade on a stock exchange.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(126, 'Collection Agency', ' A collection agency is a company used by lenders, or creditors, to recover funds that are past due, or from accounts that are in default. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(127, 'Commercial Paper', 'Commercial paper is a commonly used type of unsecured, shortterm debt instrument issued by corporations, typically used for the financing of payroll, accounts payable and inventories, and meeting other shortterm liabilities. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(128, 'Commingled Fund', 'A commingled fund is a portfolio consisting of assets from several accounts that are blended together. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(129, 'Common Stock', 'Common stock is a security that represents ownership in a corporation. Holders of common stock elect the board of directors and vote on corporate policies. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(130, 'Compound Annual Growth Rate ГўвӮ¬вҖң CAGR', 'Compound annual growth rate (CAGR) is the rate of return that would be required for an investment to grow from its beginning balance to its ending balance, assuming the profits were reinvested at the end of each year of the investments lifespan. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(131, 'Compound Interest', 'Compound interest (or compounding interest) is interest calculated on the initial principal, which also includes all of the accumulated interest from previous periods on a deposit or loan.  ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(132, 'Compounded Annualised Growth Rate (CAGR)', 'It is the return of a fund from one point to the other after factoring in the time for holding investments. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(133, 'Compounding', ' Compounding is the process in which an assets earnings, from either capital gains or interest, are reinvested to generate additional earnings over time. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(134, 'Consolidated Account Statement (CAS)', ' CAS refers to a single account statement which combines the transactions in all folios of an investor across all the mutual fund schemes fund houses.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(135, 'Consumer Goods', ' Consumer goods are products bought for consumption by the average consumer.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(136, 'Consumer Price Index (CPI)', ' The Consumer Price Index (CPI) is a measure that examines the weighted average of prices of a basket of consumer goods and services, such as transportation, food, and medical care. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(137, 'Contingent Deferred Sales Charge (CDSC) ГўвӮ¬вҖң', 'A backend sales charge imposed when shares are redeemed from a fund. This fee usually declines over time. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(138, 'Corporate Bond', ' A longterm bond issued by a corporation to raise outside capital.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(139, 'Corporate Tax', 'A corporate tax is a levy placed on a firms profit by the government. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(140, 'Corpus', ' The term corpus refers to the principal of an estate or trust. Corpus can also refer to the principal of a bond.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(141, 'Cost Basis', 'Cost basis is the original value of an asset for tax purposes, usually the purchase price, adjusted for stock splits, dividends and return of capital distributions.  ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(142, 'Cost of Capital', 'Cost of capital is the required return necessary to make a capital budgeting project, such as building a new factory, worthwhile. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(143, 'Cost of Equity', ' The cost of equity is the return a company requires to decide if an investment meets capital return requirements. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(144, 'Cost-Push Inflation', 'Costpush inflation occurs when overall prices increase (inflation) due to increases in the cost of wages and raw materials. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(145, 'Country breakdown', ' Breakdown of securities in a portfolio by country.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(146, 'Coupon Rate', ' A coupon rate is the yield paid by a fixedincome security a fixedincome securitys coupon rate is simply just the annual coupon payments paid by the issuer relative to the bonds face or par value. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(147, 'Credit Quality', 'While investing in debt funds, investors should gauge the credit quality of the instruments in the portfolio. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(148, 'Credit Rating', ' A credit rating is a quantified assessment of the creditworthiness of a borrower in general terms or with respect to a particular debt or financial obligation.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(149, 'KBW Bank Index', ' The KBW Bank Index tracks the stock prices of prominent banking companies in an attempt to be a bellwether for banking industry watchers.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(150, 'Credit Score', 'A credit score is a number ranging from 300850 that depicts a consumers creditworthiness.  ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(151, 'Credit Union', ' A credit union is a type of financial cooperative that provides traditional banking services. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(152, 'Cross Elasticity of Demand', 'The cross elasticity of demand is an economic concept that measures the responsiveness in the quantity demanded of one good when the price for another good changes.  ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(153, 'Crude Oil', 'Crude oil is a naturally occurring, unrefined petroleum product composed of hydrocarbon deposits and other organic materials. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(154, 'Cryptocurrency', 'A cryptocurrency is a digital or virtual currency that is secured by cryptography, which makes it nearly impossible to counterfeit or doublespend. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(155, 'Currency', 'Currency is a medium of exchange for goods and services. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(156, 'Current Ratio', 'The current ratio is a liquidity ratio that measures a companys ability to pay shortterm obligations or those due within one year. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(157, 'Current Yield', ' Current yield is an investments annual income (interest or dividends) divided by the current price of the security.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(158, 'Custodian', 'A custodian is a financial institution that holds customers securities for safekeeping in order to minimize the risk of their theft or loss.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(159, 'Daily dividend factor (date)', 'Daily dividend distributed by a money market mutual fund.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(160, 'DAX Stock Index', 'DAX is a stock index that represents 30 of the largest and most liquid German companies that trade on the Frankfurt Exchange.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(161, 'Deadweight Loss', 'A deadweight loss is a cost to society created by market inefficiency, which occurs when supply and demand are out of equilibrium.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(162, 'Kuala Lumpur Stock Exchange (KLS)', ' The Kuala Lumpur Stock Exchange (KLSE) was the precursor exchange to the Bursa Malaysia Exchange.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(163, 'Laggard', ' A laggard is a stock or security that is underperforming relative to its benchmark or peers. A laggard is the opposite of a leader.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(164, 'Land Trust', ' Land trusts are organizations that take legal ownership, stewardship, or partial control over property at the behest of the landowner.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(165, 'Land Value', ' Land value is the value of the land, as well as any improvements that have been made to it.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(166, 'Lapse', ' A lapse is when the benefits and everything else stated in a contract no longer remain active because the contract holder has failed to honor requirements and conditions set forth by a contract or agreement.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(167, 'Large Cap (Big Cap)', ' Large cap (sometimes called big cap) refers to a company with a market capitalization value of more than 10 billion. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(168, 'Legislative Risk', ' Legislative risk is the potential that regulations or legislation by the government could significantly alter the business prospects of one or more companies.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(169, 'Lender of Last Resort', ' A lender of last resort provides emergency credit to financial institutions that are struggling financially and near collapse.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(170, 'Leverage Ratio', ' A leverage ratio is any one of several financial measurements that assesses the ability of a company to meet its financial obligations.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(171, 'Leveraged Loan Index (LLI)', ' A leveraged loan index (LLI) is a marketweighted index that tracks the performance of institutional leveraged loans. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(172, 'Liabilities', ' Any claim for money against the assets of a company, such as bills of creditors, income tax payable, debenture redemption, interest on secured and unsecured loans, etc.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(173, 'LIBOR Curve', ' The LIBOR curve is the graphical representation of the interest rate term structure of various maturities of the London Interbank Offered Rate, commonly known as LIBOR. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(174, 'Dark Pool', 'A dark pool is a privately organized financial forum or exchange for trading securities. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(175, 'Licensing Agreement', ' A licensing agreement is a written contract between two parties, in which a property owner permits another party to use that property under a specific set of parameters.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(176, 'Life Income Fund (LIF)', ' A life income fund (LIF) is a type of registered retirement income fund (RRIF) offered in Canada that can be used to hold lockedin pension funds as well as other assets for eventual payout as retirement income.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(177, 'Life-Cycle Fund', ' Lifecycle funds are assetallocation funds in which the share of each asset class is automatically adjusted to lower risk as the desired retirement date approaches.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(178, 'Limited Power of Attorney (LPOA)', ' A limited power of attorney allows a portfolio manager to make routine decisions without contacting the account holder.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(179, 'Lipper Indexes', ' Lipper Indexes are indexes that track the financial performance of different types of managed fund strategies. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(180, 'Liquidate', ' Liquidate means to convert assets into cash or cash equivalents by selling them on the open market.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(181, 'Liquidating Dividend', ' A liquidating dividend is a type of payment that a corporation makes to its shareholders during a partial or full liquidation. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(182, 'Liquidation Margin', ' A liquidation margin is the current value of a margin account based on its cash deposits and the most recent market value of its open positions.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(183, 'Liquidity', ' The ability to have ready access to invested money. Mutual funds are liquid because their shares can be redeemed for current value (which may be more or less than the original cost) on any business day.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(184, 'Liquidity Coverage Ratio ГўвӮ¬вҖң LCR', ' The liquidity coverage ratio (LCR) refers to the proportion of highly liquid assets held by financial institutions, to ensure their ongoing ability to meet shortterm obligations.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(185, 'Liquidity Event', ' A liquidity event is an acquisition, merger, initial public offering or other event that allows founders and early investors in a company to cash out some or all of their ownership shares.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(186, 'Liquidity Premium', ' Liquidity premium is a premium demanded by investors when any given security cannot be easily converted into cash for its fair market value.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(187, 'Liquidity Ratio', ' Liquidity ratios are an important class of financial metrics used to determine a debtors ability to pay off current debt obligations without raising external capital.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(188, 'Listing Agreement', ' A listing agreement is between a real estate broker and the property owner to find a buyer of that property.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(189, 'Listing Requirements', ' Listing requirements comprise the various criteria and minimum standards established by stock exchanges.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(190, 'Load', ' A sales charge assessed by certain mutual funds (load funds) to cover selling costs. A front end load is charged at the time of purchase. A backend load is charged at the time of sale.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(191, 'Locked In', ' An investor is locked in when he or she is unwilling or unable to trade a security because regulations, taxes or penalties prevent it.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(192, 'Dealer Market', 'A dealer market is a financial market mechanism wherein multiple dealers post prices at which they will buy or sell a specific security of instrument.  ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(193, 'Death Benefit', 'A death benefit is a payout to the beneficiary of a life insurance policy, annuity, or pension when the insured or annuitant dies.  ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(194, 'Lock-Up Agreement', ' A lockup agreement temporarily prevents company insiders from selling shares following an IPO.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38');
INSERT INTO `mpx_fund_dictionary` (`fd_id`, `title`, `description`, `status`, `created_id`, `updated_id`, `created_at`, `updated_at`, `migration_at`) VALUES
(195, 'Debenture', 'Bonds issued by a company bearing a fixed rate of interest usually payable half yearly on specific dates and principal amount repayable on a particular date on redemption of the debentures. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(196, 'Debit', 'A debit is an accounting entry that results in either an increase in assets or a decrease in liabilities on a companys balance sheet. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(197, 'Lock-Up Period', ' Lockup periods are when investors cannot sell particular shares or securities.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(198, 'London Stock Exchange (LSE)', ' The London Stock Exchange (LSE) is the primary stock exchange in the U.K. and the largest in Europe..', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(199, 'Long Term', ' Long term refers to the extended period of time that an asset is held.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(200, 'Long/Short Fund', '  A longshort fund is a type of mutual fund or hedge fund that takes both long and short positions in investments typically from a specific market segment.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(201, 'Debit Note', ' A debit note is a document used by a vendor to inform the buyer of current debt obligations, or a document created by a buyer when returning goods received on credit. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(202, 'Long-Term Assets', ' Longterm assets are investments in a company that will benefit the company for many years.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(203, 'Debt', 'Debt is an amount of money borrowed by one party from another.  ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(204, 'Debt Consolidation', 'The term debt consolidation refers to the act of taking out a new loan to pay off other liabilities and consumer debts, generally unsecured ones. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(205, 'Long-Term Growth (LTG)', ' Longterm growth (LTG) is an investment strategy that aims to increase the value of a portfolio over a multiyear time frame. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(206, 'Long-Term Investments', ' A longterm investment is an account a company plans to keep for at least a year such as stocks, bonds, real estate, and cash.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(207, 'Debt Fund', ' A debt fund is an investment pool, such as a mutual fund or exchangetraded fund, in which the core holdings comprise fixed income investments. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(208, 'Macaulay Duration', ' The Macaulay duration is the weighted average term to maturity of the cash flows from a bond. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(209, 'Debt Ratio Definition', ' The debt ratio is a financial ratio that measures the extent of a companys leverage.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(210, 'Debtor', ' A debtor is a company or individual who owes money.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(211, 'Macro Environment', ' The macroenvironment refers to the broader condition of an economy as opposed to specific markets.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(212, 'Magic Formula Investing', ' Magic formula investing is a successfully backtested strategy that can increase your chances of outperforming the market.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(213, 'Management Fee', ' Management fees are the cost of having an investment fund professionally managed by an investment manager. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(214, 'Mark to Market (MTM)', ' Mark to market can present a more accurate figure for the current value of a companys assets, based on what the company might receive in exchange for the asset under current market conditions.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(215, 'Market Cycles', ' A cycle refers to trends or patterns that emerge during different business environments.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(216, 'Market Depth', ' Market depth is the markets ability to sustain relatively large market orders without impacting the price of the security.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(217, 'Market Index', ' Market indexes provide a broad representative portfolio of investment holdings.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(218, 'Market Maker', ' A market maker is a individual market participant or member firm of an exchange that also buys and sells securities for its own account, at prices it displays in its exchanges trading system, with the primary goal of profiting on the bidask spread, which is the amount by which the ask price exceeds the bid price a market asset.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(219, 'Market Neutral', ' A marketneutral strategy is a type of investment strategy undertaken by an investor or an investment manager that seeks to profit from both increasing and decreasing prices in one or more markets, while attempting to completely avoid some specific form of market risk.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(220, 'Market Portfolio', ' A market portfolio is a theoretical, diversified group of every type of investment in the world, with each asset weighted in proportion to its total presence in the market.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(221, 'Market price', ' The current price of an asset.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(222, 'Market Risk Premium', ' The market risk premium is the difference between the expected return on a market portfolio and the riskfree rate.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(223, 'Market Timing', ' Market timing is an investment or trading strategy in which a market participant attempts to beat the stock market by predicting its movements and buying and selling accordingly.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(224, 'Market Value', ' Market value is the price an asset fetches in the market and is commonly used to refer to market capitalization.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(225, 'Maturity', ' The date specified in a note or bond on which the debt is due and payable.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(226, 'Maturity distribution', ' The breakdown of a portfolios assets based on the time frame when the investments will mature. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(227, 'Debt-To-Equity Ratio ГўвӮ¬вҖң D/E', ' The debttoequity (DE) ratio is calculated by dividing a companys total liabilities by its shareholder equity.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(228, 'Debt-to-GDP Ratio', ' The debttoGDP ratio is the metric comparing a countrys public debt to its gross domestic product (GDP).', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(229, 'Maximum Drawdown (MDD)', '  Maximum drawdown (MDD) is a measure of an assets largest price drop from a peak to a trough.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(230, 'Decoupling', ' Decoupling is when the returns of one asset class diverges from their expected or normal pattern of correlation with others.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(231, 'Medallion Signature Guarantee', ' A medallion signature guarantee is one of several special certification stamps that guarantees a signature that authorizes a transfer of securities is authentic.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(232, 'Deed', ' A deed is a signed legal document that grants its holder specific rights to an assetprovided that he or she meets a number of conditions.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(233, 'Default', ' Default is the failure to repay a debt including interest or principal on a loan or security. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(234, 'Median Market Cap', ' The midpoint of market capitalization (market price multiplied by the number of shares outstanding) of the stocks in a portfolio, where half the stocks have higher market capitalization and half have lower.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(235, 'Default Rate', ' The default rate is the percentage of all outstanding loans that a lender has written off after a prolonged period of missed payments. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(236, 'Defensive Stock', ' A defensive stock is a stock that provides consistent dividends and stable earnings regardless of the state of the overall stock market. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(237, 'Deficit', ' A deficit is an amount by which a resource, especially money, falls short of what is required.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(238, 'Melt Up', ' A melt up is a sudden rise in the price of an asset class due to investment by a stampede of investors interested in profiting from the gains in price.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(239, 'Deflation', ' Deflation is a general decline in prices for goods and services, typically associated with a contraction in the supply of money and credit in the econom.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(240, 'Delivery Versus Payment (DVP)', 'Delivery versus payment (DVP) is a securities industry settlement method that guarantees the transfer of securities only happens after payment has been made.  ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(241, 'Delta Neutral', 'Delta neutral is a portfolio strategy utilizing multiple positions with balancing positive and negative deltas so that the overall delta of the assets in question totals zero. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(242, 'Demand', ' Demand is an economic principle referring to a consumers desire to purchase goods and services and willingness to pay a price for a specific good or service.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(243, 'Metrics', ' Metrics are measures of quantitative assessment commonly used for comparing, and tracking performance or production.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(244, 'Micro Cap', ' A microcap is a publiclytraded company in the United States that has a market capitalization between approximately 50 million and 300 million. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(245, 'Mid-Cap', '  Midcap is the term given to companies with a market capitalization (value) between 2 and 10 billion.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(246, 'Demand Curve', 'The demand curve is a graphical representation of the relationship between the price of a good or service and the quantity demanded for a given period of time.  ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(247, 'Mid-Cap Fund', ' A midcap fund is a pooled investment, such as a mutual fund, that focuses on companies with a market capitalization in the middle range of listed stocks.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(248, 'Demand Shock', ' A demand shock is a sudden and surprise event that dramatically increases or decreases demand for particular goods or services, usually on a temporary basis.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(249, 'Dematerialization (DEMAT)', ' Dematerialization (DEMAT) is the move from physical certificates to electronic bookkeeping..', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(250, 'Middle East and North Africa (MENA)', ' The Middle East and North Africa (MENA) includes approximately 19 countries, according to World Atlas.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(251, 'Demonetization', 'Demonetization is the act of stripping a currency unit of its status as legal tender.  ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(252, 'Middle-Income Countries (mics)', ' Middleincome countries are those with 1,026 to 12,475 in per capita GNI. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(253, 'Depreciation Recapture', ' Depreciation recapture is the gain realized by the sale of depreciable capital property that must be reported as ordinary income for tax purposes. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(254, 'Depth of Market (DOM)', 'Depth of market  DOM is a window that shows the number of open buy and sell orders for a security or currency at different prices. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(255, 'Minimum Additional Amount', ' This is the minimum investment amount for an existing investor in a mutual fund scheme.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(256, 'Deregulation', ' Deregulation is the reduction or elimination of government power in a particular industry, usually enacted to create more competition within the industry. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(257, 'Derivative', ' A derivative is a financial security with a value that is reliant upon or derived from, an underlying asset or group of assetsa benchmark. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(258, 'Diamonds', ' Diamonds is an informal term for an indexbased exchangetraded fund (ETF) known as the SPDR Dow Jones Industrial Average ETF.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(259, 'Digital Currency', ' Digital currency is a form of currency that is available only in digital or electronic form, and not in physical form.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(260, 'Modern Portfolio Theory (MPT)', ' Modern portfolio theory (MPT) is a theory on how riskaverse investors can construct portfolios to optimize or maximize expected return based on a given level of market risk, emphasizing that risk is an inherent part of higher reward.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(261, 'Direct Investment', ' Direct investment, more commonly referred to as foreign direct investment (FDI), refers to an investment in a foreign business enterprise designed to acquire a controlling interest in this enterprise. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(262, 'Direct Market Access (DMA)', ' Direct market access refers to access to the electronic facilities and order books of financial market exchanges that facilitate daily securities transactions.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(263, 'Modified Duration', ' Modified duration is the price sensitivity and the percentage chanin price for a unit change in yield', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(264, 'Dirty Price', ' A dirty price is a bond pricing quote, which refers to the cost of a bond that includes accrued interest based on the coupon rate. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(265, 'Disclosure', ' In the financial world, disclosure refers to the timely release of all information about a company that may influence an investors decision.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(266, 'Money Manager', ' A money manager is a person or financial firm that manages the securities portfolio of individual or institutional investors.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(267, 'Discount', ' When a security is quoted at a price below its nominal or face value, it is said to be at a discount.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(268, 'Discount Broker', ' A discount broker is a stockbroker who carries out buy and sell orders at a reduced commission rate. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(269, 'Money Market', ' The money market involves the purchase and sale of large volumes of very shortterm debt products, such as overnight reserves or commercial paper.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(270, 'Discount Yield', ' The discount yield is a way of calculating a bonds return when it is sold at a discount to its face value, expressed as a percentage. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(271, 'Money Market Fund', ' A money market fund is a type of mutual fund that invests in highquality, shortterm debt instruments, cash, and cash equivalents.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(272, 'Discounted Cash Flow (DCF)', ' Discounted cash flow (DCF) is a valuation method used to estimate the value of an investment based on its future cash flows.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(273, 'Discretionary Investment Management', ' Discretionary investment management is a form of investment management in which buy and sell decisions are made by a portfolio manager or investment counselor for the clients account. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(274, 'Money-Weighted Rate of Return', ' The moneyweighted rate of return is a measure of the performance of an investment. The moneyweighted rate of return is calculated by finding the rate of return that will set the present values of all cash flows equal to the value of the initial investment.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(275, 'Disintermediation', ' Disintermediation is the process of removing the middleman or intermediary from future transactions.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(276, 'Morningstar Risk Rating', ' The Morningstar risk rating is a ranking given by research firm Morningstar to publicly traded mutual funds and exchangetraded funds (etfs).', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(277, 'Disinvestment', ' Disinvestment is the action of an organization or government selling or liquidating an asset or subsidiary. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(278, 'MSCI All Country World Index (ACWI)', ' The MSCI ACWI is a market capitalization weighted index designed to provide a broad measure of equitymarket performance throughout the world. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(279, 'Disruptive Technology', ' Disruptive technology is an innovation that significantly alters the way that consumers, industries, or businesses operate. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(280, 'Multi-Asset Class', ' A multiasset class is primarily built to limit downside risk by broadening an investors exposure to different sectors.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(281, 'Distressed Sale', 'A distressed sale occurs when a property, stock, or another asset must be sold quickly.  ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(282, 'Distressed Securities', ' Distressed securities are financial instruments issued by a company that is near to or currently going through bankruptcy.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(283, 'Distribution', 'The word distribution has several meanings in the financial world, most of them pertaining to the payment of assets from a fund, account, or individual security to an investor or beneficiary. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(284, 'Distribution schedule', 'A tentative distribution schedule of a mutual funds dividends and capital gains. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(285, 'Multilateral Development Bank (MDB)', ' Multilateral development banks (mdbs) originated in the aftermath of World War II to rebuild warravaged nations and stabilize the global financial system.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(286, 'Diversification', 'Diversification is a risk management strategy that mixes a wide variety of investments within a portfolio.  ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(287, 'Multinational Corporation (MNC)', ' Multinational corporations participate in business in two or more countries.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(288, 'Mutual Fund', ' A mutual fund is a type of investment vehicle consisting of a portfolio of stocks, bonds, or other securities.  ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(289, 'Dividend', ' A dividend is the distribution of a portion of the companys earnings, decided and managed by the companys board of directors, and paid to a class of its shareholders.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(290, 'Dividend Option', ' Dividend option indicates that there would be intermediate payments to the investor in form of dividends. The rate and time of payment though is not prefixed, it depends entirely on the fund performance. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(291, 'Nature of Scheme', ' The investment objective and underlying investments determine the nature of the mutual fund scheme.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(292, 'Dividend Payout Ratio', ' The dividend payout ratio is the ratio of the total amount of dividends paid out to shareholders relative to the net income of the company.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(293, 'Dividend Per Share ГўвӮ¬вҖң DPS', ' Dividend per share (DPS) is the sum of declared dividends issued by a company for every ordinary share outstanding. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(294, 'NAV', ' The NAV or the net asset value is the total asset value per unit of the mutual fund after deducting all related and permissible expenses.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(295, 'Dividend Policy', ' Dividend policy is the policy a company uses to structure its dividend payout to shareholders. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(296, 'Net Asset Value', ' Net asset value or NAV is the most commonly associated word with mutual funds and widely used by investors while buying and selling mutual fund units.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(297, 'Dividend Rate', ' The dividend rate is the total expected dividend payments from an investment, fund or portfolio expressed on an annualized basis plus any additional nonrecurring dividends that an investor may receive during that period.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(298, 'Net Worth', ' The aggregate value of the paid up equity capital and free reserves (excluding reserves created out of revaluation), reduced by the aggregate value of accumulated losses and deferred expenditure not written off, including miscellaneous expenses not written of.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(299, 'NFO', ' A new fund offer (NFO) refers to the initial sale of fund shares issued by an investment company to investors.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(300, 'OFFERING PRICE', ' AN OFFERING PRICE REFERS TO THE PRICE OF A STOCK SET BY AN INVESTMENT BANK DURING THE IPO PROCESS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(301, 'OFFSHORE MUTUAL FUND', ' AN OFFSHORE MUTUAL FUND IS AN INVESTMENT VEHICLEBASED IN AN OFFSHORE LOCATION OUTSIDE THE JURISDICTION OF THE UNITED STATES, OFTEN USED AS A TAX HAVEN.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(302, 'ONE NIGHT STAND INVESTMENT', ' A ONE NIGHT STAND INVESTMENT IS A PURCHASED SECURITY THAT WAS INTENDED FOR A LONGTERM INVESTMENT, BUT IS INSTEAD SOLD VERY QUICKLY, MANY TIMES AS SOON AS THE NEXT DAY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(303, 'OPEN OFFER', ' IN AN OPEN OFFER, A SHAREHOLDER IS ALLOWED TO PURCHASE STOCK AT A PRICE THAT IS LOWER THAN THE CURRENT MARKET PRICE. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(304, 'OPEN-END FUND', ' AN OPENEND FUND IS AN INVESTMENT VEHICLE THAT USES POOLED ASSETS, WHICH ALLOWS FOR ONGOING NEW CONTRIBUTIONS AND WITHDRAWALS FROM INVESTORS OF THE POOL.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(305, 'Dividend Reinvestment PlanГўвӮ¬вҖқDRIP', ' A dividend reinvestment plan (DRIP) is a program that allows investors to reinvest their cash dividends into additional shares or fractional shares of the underlying stock on the dividend payment date. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(306, 'Dividend Yield', ' The dividend yield is the ratio of a companys annual dividend compared to its share price. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(307, 'OPENING PRICE', ' THE OPENING PRICE IS THE PRICE AT WHICH A SECURITY FIRST TRADES WHEN AN EXCHANGE OPENS FOR THE DAY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(308, 'Dividends', ' Payment made to shareholders, usually once or twice a year out of a companys profit after tax.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(309, 'Dividends Received Deduction (DRD)', ' The dividends received deduction (DRD) is a federal tax deduction in the U.S. that is given to certain corporations that get dividends from related entities. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(310, 'Dogs of the Dow', 'Dogs of the Dow is an investment strategy that attempts to beat the Dow Jones Industrial Average (DJIA) each year by optimizing towards highyield investments.. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(311, 'Dow Jones Industrial Average (DJIA)', ' The Dow Jones Industrial Average (DJIA) is an index that tracks 30 large, publiclyowned blue chip companies trading on the New York Stock Exchange (NYSE) and the NASDAQ. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(312, 'EAFE Index', ' The EAFE is a broad market index of stocks located within countries in Europe, Australasia, and the Middle East. Developed by Morgan Stanley Capital International (MSCI) in 1969, the EAFE Index contains more than 900 stocks from 21 countries. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(313, 'Earnest Money', ' Earnest money is essentially a deposit a seller makes on a home they want to purchase. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(314, 'Earnings Credit Rate (ECR)', ' The earnings credit rate (ECR) is the imputed interest rate calculated by banks too account for money that they hold in noninterest bearing accounts.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(315, 'OPTIMIZED PORTFOLIO AS LISTED SECURITIES (OPALS)', ' OPTIMIZED PORTFOLIO AS LISTED SECURITIES IS A SINGLECOUNTRY EQUITY INDEX THAT CONTAINS FEWER HOLDINGS THAN THE BENCHMARKED INDEX.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(316, 'Earnings Per Share ГўвӮ¬вҖң EPS', ' Earnings per share (EPS) is a companys net profit divided by the number of common shares it has outstanding. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(317, 'Effective Annual Interest Rate', ' The effective annual interest rate is the real return on a savings account or any interestpaying investment when the effects of compounding over time are taken into account.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(318, 'Effective Duration', ' Effective duration is a duration calculation for bonds that have embedded options. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(319, 'Effective Gross Income (EGI)', ' Effective Gross Income is the Potential Gross Rental Income plus other income minus vacancy and credit costs of a rental property.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(320, 'Effective Yield', ' The effective yield is calculated as the bonds coupon payments divided by the bonds current market value. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(321, 'Efficiency Ratio', ' The efficiency ratio is typically used to analyze how well a company uses its assets and liabilities internally.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(322, 'Efficient Frontier', ' Efficient frontier comprises investment portfolios that offer the highest expected return for a specific level of risk.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(323, 'Electronic Money', ' Electronic money is currency that is stored in banking computer systems.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(324, 'Emergency Banking Act of 1933', ' The Emergency Banking Act of 1933 was a bill passed in the midst of the Great Depression that took steps to stabilize and restore confidence in the U.S. banking system. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(325, 'Option', ' The contractual right, but not obligation, to buy (call option) or sell (put option) a specified amount of underlying security at a fixed price (strike price) before or at a designated future date (expiration date).', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(326, 'OPTION POOL', ' AN OPTION POOL REFERS TO A BLOCK OF COMPANY EQUITY THAT HAS BEEN RESERVED FOR EARLY INVESTORS OR EMPLOYEES OF A STARTUP COMPANY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(327, 'ORDERLY MARKET', ' AN ORDERLY MARKET IS ANY MARKET IN WHICH THE SUPPLY AND DEMAND ARE REASONABLY EQUAL.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(328, 'ORDINARY DIVIDENDS', ' ORDINARY DIVIDENDS ARE A SHARE OF A COMPANYS PROFITS PASSED ON TO THE SHAREHOLDERS PERIODICALLY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(329, 'ORDINARY SHARES', ' ORDINARY SHARES PROVIDE INVESTORS WITH VOTING RIGHTS (ONE VOTE PER SHARE) AND REPRESENT PROPORTIONATE OWNERSHIP OF A COMPANY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(330, 'OSLO STOCK EXCHANGE (OSL) .OL', ' THE OSLO STOCK EXCHANGE (OSL) .OL, KNOWN IN NORWEGIAN AS OSLO BRS, IS THE MAJOR STOCK MARKET IN NORWAY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(331, 'OUTWARD DIRECT INVESTMENT (ODI)', ' AN OUTWARD DIRECT INVESTMENT (ODI) IS A BUSINESS STRATEGY IN WHICH A DOMESTIC FIRM EXPANDS ITS OPERATIONS TO A FOREIGN COUNTRY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(332, 'OVER-55 HOME SALE EXEMPTION', ' THE OVER55 HOME SALE EXEMPTION WAS A TAX LAW THAT PROVIDED HOMEOWNERS OVER THE AGE OF 55 WITH A ONETIME CAPITAL GAINS EXCLUSION.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(333, 'OVERALLOTMENT', ' AN OVERALLOTMENT IS AN OPTION COMMONLY AVAILABLE TO UNDERWRITERS THAT ALLOWS THE SALE OF ADDITIONAL SHARES THAT A COMPANY PLANS TO ISSUE IN AN INITIAL PUBLIC OFFERING OR SECONDARYFOLLOWON OFFERING.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(334, 'OVERHANG', ' OVERHANG IS THE TOTAL DILUTION FOR COMMON SHAREHOLDERS DUE TO EMPLOYEE STOCK OPTION AWARDS. IT IS GENERALLY EXPRESSED AS A PERCENTAGE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(335, 'OVERLAY', ' OVERLAY REFERS TO AN ASSET MANAGEMENT STYLE THAT USES SOFTWARE TO HARMONIZE AN INVESTORS SEPARATELY MANAGED ACCOUNTS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(336, 'OVERNIGHT RATE', ' OVERNIGHT RATES ARE THE RATES AT WHICH BANKS LEND FUNDS TO EACH OTHER AT THE END OF THE DAY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(337, 'OVERSEAS PRIVATE INVESTMENT CORPORATION (OPIC)', ' A U.S. GOVERNMENT AGENCY THAT ASSISTS BUSINESSES LOOKING TO INVEST ABROAD.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(338, 'OVERVALUED', ' AN OVERVALUED STOCK HAS A CURRENT PRICE THAT IS NOT JUSTIFIED BY ITS EARNINGS OUTLOOK, TYPICALLY ASSESSED BY ITS PE RATIO.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(339, 'OVERWEIGHT', ' OVERWEIGHT IS AN OUTSIZED INVESTMENT IN A PARTICULAR ASSET, ASSET TYPE, OR SECTOR WITHIN A PORTFOLIO.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(340, 'P/B RATIO', ' THE PRICE PER SHARE OF A STOCK DIVIDED BY ITS BOOK VALUE (NET WORTH) PER SHARE. FOR A STOCK PORTFOLIO, THE RATIO IS THE WEIGHTED AVERAGE PRICETOBOOK RATIO OF THE STOCKS IT HOLDS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(341, 'P/E 10 RATIO', ' THE PE 10 RATIO IS A VALUATION MEASURE, GENERALLY APPLIED TO BROAD EQUITY INDICES, THAT USES REAL PERSHARE EARNINGS OVER A 10YEAR PERIOD.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(342, 'PAR VALUE', ' PAR VALUE IS THE AMOUNT ORIGINALLY PAID FOR A BOND AND THE AMOUNT THAT WILL BE REPAID AT MATURITY. BONDS ARE TYPICALLY SOLD IN MULTIPLES OF 1,000.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(343, 'PARITY PRICE', ' PARITY PRICE REFERS TO THE CONCEPT OF COMPARING TWO ASSETS EQUAL IN VALUE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(344, 'PARTICIPATING PREFERRED STOCK', ' PARTICIPATING PREFERRED STOCK ARE PREFERRED SHARES THAT PAY BOTH PREFERRED DIVIDENDS PLUS AN ADDITIONAL DIVIDEND TO THEIR SHAREHOLDERS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(345, 'PARTICIPATORY NOTES', ' PARTICIPATORY NOTES ALSO REFERRED TO AS PNOTES, OR PNS, ARE FINANCIAL INSTRUMENTS REQUIRED BY INVESTORS OR HEDGE FUNDS TO INVEST IN INDIAN SECURITIES WITHOUT HAVING TO REGISTER WITH THE SECURITIES AND EXCHANGE BOARD OF INDIA (SEBI).', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(346, 'PASSIVE FOREIGN INVESTMENT COMPANYГўвӮ¬вҖқPFIC', ' A FOREIGN CORPORATION IS A DEEMED PASSIVE FOREIGN INVESTMENT COMPANY (PFIC) IF (1) 75 OR MORE OF ITS GROSS INCOME IS FROM NONBUSINESS OPERATIONAL ACTIVITIES (THE INCOME TEST) OR (2) AT LEAST 50 OF ITS AVERAGE PERCENTAGE OF ASSETS IS HELD FOR THE PRODUCTION OF PASSIVE INCOME (THE ASSET TEST).', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(347, 'PASSIVE INCOME', ' PASSIVE INCOME IS INCOME THAT IS EARNED FROM RENTAL PROPERTY OR AN ENTERPRISE IN WHICH THE INVESTOR IS NOT ACTIVELY INVOLVED.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(348, 'PASSIVE INVESTING', ' PASSIVE INVESTING BROADLY REFERS TO A BUYANDHOLD PORTFOLIO STRATEGY FOR LONGTERM INVESTMENT HORIZONS, WITH MINIMAL TRADING IN THE MARKET.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(349, 'PAYOUT RATIO', ' THE PAYOUT RATIO, ALSO KNOWN AS THE DIVIDEND PAYOUT RATIO, SHOWS THE PERCENTAGE OF A COMPANYS EARNINGS PAID OUT AS DIVIDENDS TO SHAREHOLDERS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(350, 'PEER GROUP', ' A PEER GROUP REFERS TO LIKE INDIVIDUALS OR ORGANIZATIONS THAT SHARE SEVERAL SIMILARITIES, MAKING THEM EASILY COMPARABLE AS A GROUP.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(351, 'PENNY STOCK', ' A PENNY STOCK REFERS TO A SMALL COMPANYS STOCK THAT TYPICALLY TRADES FOR LESS THAN 5 PER SHARE. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(352, 'PERSEROAN TERBATAS (PT)', ' PT IS AN ACRONYM FOR PERSEROAN TERBATAS, A TERM THAT REPRESENTS A LIMITED LIABILITY COMPANY IN INDONESIA.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(353, 'PHANTOM STOCK PLAN', ' A PHANTOM STOCK PLAN, OR SHADOW STOCK IS A FORM OF COMPENSATION OFFERED TO UPPER MANAGEMENT THAT CONFERS THE BENEFITS OF OWNING COMPANY STOCK WITHOUT THE ACTUAL OWNERSHIP OR TRANSFER OF ANY SHARES.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(354, 'PINK SHEETS', ' PINK SHEETS REFER TO A LISTING SERVICE FOR STOCKS THAT TRADE VIA OVERTHECOUNTER (OTC).', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(355, 'PIOTROSKI SCORE', ' THE PIOTROSKI SCORE IS A DISCRETE SCORE BETWEEN 09 THAT REFLECTS NINE CRITERIA USED TO DETERMINE THE STRENGTH OF A FIRMS FINANCIAL POSITION.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(356, 'PLAIN VANILLA', ' PLAIN VANILLA IS THE MOST BASIC VERSION OF A FINANCIAL INSTRUMENT AND COMES WITH NO SPECIAL FEATURES.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(357, 'PLOWBACK RATIO', '  THE PLOWBACK RATIO IS A FUNDAMENTAL ANALYSIS RATIO THAT MEASURES HOW MUCH EARNINGS ARE RETAINED AFTER DIVIDENDS ARE PAID OUT  IT IS AN INDICATOR OF HOW MUCH PROFIT IS RETAINED IN A BUSINESS RATHER THAN PAID OUT TO INVESTORS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(358, 'POOLED FUNDS', ' POOLED FUNDS AGGREGATE CAPITAL FROM A NUMBER OF INDIVIDUALS, INVESTING AS ONE GIANT PORTFOLIO.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(359, 'PORTFOLIO', ' A PORTFOLIO IS A BASKET OF ASSETS THAT CAN INCLUDE STOCKS, BONDS, COMMODITIES, CURRENCIES, CASH EQUIVALENTS, AS WELL AS THEIR FUND COUNTERPARTS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(360, 'PORTFOLIO ALLOCATION', ' AMOUNT OF ASSETS IN A PORTFOLIO SPECIFICALLY DESIGNATED FOR A CERTAIN TYPE OF INVESTMENT. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(361, 'PORTFOLIO INVESTMENT', ' A PORTFOLIO INVESTMENT IS AN ASSET THAT IS PURCHASED IN THE EXPECTATION THAT IT WILL EARN A RETURN OR GROW IN VALUE, OR BOTH.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(362, 'PORTFOLIO MANAGEMENT', ' PORTFOLIO MANAGEMENT INVOLVES BUILDING AND OVERSEEING A SELECTION OF INVESTMENTS THAT WILL MEET THE LONGTERM FINANCIAL GOALS AND RISK TOLERANCE OF AN INVESTOR.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(363, 'PORTFOLIO MANAGER', ' A PORTFOLIO MANAGER IS A PERSON OR GROUP OF PEOPLE RESPONSIBLE FOR INVESTING A MUTUAL, EXCHANGETRADED OR CLOSEDEND FUNDS ASSETS, IMPLEMENTING ITS INVESTMENT STRATEGY AND MANAGING DAYTODAY PORTFOLIO TRADING.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(364, 'PORTFOLIO TURNOVER', ' PORTFOLIO TURNOVER IS A MEASURE OF HOW QUICKLY SECURITIES IN A FUND ARE EITHER BOUGHT OR SOLD BY THE FUNDS MANAGERS, OVER A GIVEN PERIOD OF TIME.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(365, 'POST-MONEY VALUATION', ' POSTMONEY VALUATION IS A COMPANYS ESTIMATED WORTH AFTER OUTSIDE FINANCING ANDOR CAPITAL INJECTIONS ARE ADDED TO ITS BALANCE SHEET.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(366, 'POST-TRADE PROCESSING', ' POSTTRADE PROCESSING OCCURS AFTER A TRADE IS COMPLETE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(367, 'POWER-DISTANCE INDEX (PDI)', ' THE POWERDISTANCE INDEX MEASURES THE DEGREE TO WHICH THE MEMBERS OF A GROUP OR SOCIETY ACCEPT THE HIERARCHY OF POWER AND AUTHORITY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(368, 'PREFERENCE SHARES', ' PREFERENCE SHARES (PREFERRED STOCK) ARE COMPANY STOCK WITH DIVIDENDS THAT ARE PAID TO SHAREHOLDERS BEFORE COMMON STOCK DIVIDENDS ARE PAID OUT.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(369, 'PREFERRED DIVIDENDS', ' A PREFERRED DIVIDEND IS A DIVIDEND THAT IS ACCRUED AND PAID ON A COMPANYS PREFERRED SHARES.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(370, 'Preferred Stock', ' Owners of this kind of stock are entitled to a fixed dividend to be paid regularly before dividend can 58 be paid on common stock.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(371, 'PRE-MARKET', ' PREMARKET TRADING IS TRADING THAT OCCURS BETWEEN 4 A.M. AND 930 A.M. EST.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(372, 'PREMIUM', ' THE AMOUNT BY WHICH A BOND OR STOCK SELLS ABOVE ITS PAR VALUE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(373, 'PRESENT VALUE ГўвӮ¬вҖң PV', ' PRESENT VALUE IS THE CONCEPT THAT STATES AN AMOUNT OF MONEY TODAY IS WORTH MORE THAN THAT SAME AMOUNT IN THE FUTURE. IN OTHER WORDS, MONEY RECEIVED IN THE FUTURE IS NOT WORTH AS MUCH AS AN EQUAL AMOUNT RECEIVED TODAY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(374, 'PRICE TO FREE CASH FLOW', ' PRICE TO FREE CASH FLOW IS AN EQUITY VALUATION METRIC THAT INDICATES A COMPANYS ABILITY TO GENERATE ADDITIONAL REVENUES. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(375, 'PRICE/EARNINGS-TO-GROWTH ГўвӮ¬вҖң PEG RATIO', ' THE PEG RATIO ENHANCES THE PE RATIO BY ADDING IN EXPECTED EARNINGS GROWTH INTO THE CALCULATION.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(376, 'PRICE-TO-BOOK (P/B RATIO)', ' THE PB RATIO MEASURES THE MARKETS VALUATION OF A COMPANY RELATIVE TO ITS BOOK VALUE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(377, 'PRICE-TO-EARNINGS RATIO ГўвӮ¬вҖң P/E RATIO', ' THE PRICEEARNINGS RATIO (PE RATIO) RELATES A COMPANYS SHARE PRICE TO ITS EARNINGS PER SHARE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(378, 'Price-To-Earnings Ratio (P/E)', ' The ratio of the market price of the share to earnings per share. This measure is used by investment experts to compare the relative merits of a number of securities.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(379, 'PRICE-TO-SALES RATIO (P/S RATIO)', ' THE PS RATIO IS A KEY ANALYSIS AND VALUATION TOOL THAT SHOWS HOW MUCH INVESTORS ARE WILLING TO PAY PER DOLLAR OF SALES FOR A STOCK. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(380, 'PRICE-WEIGHTED INDEX', ' IN A PRICEWEIGHTED STOCK INDEX, EACH COMPANYS STOCK IS WEIGHTED BY ITS PRICE PER SHARE, AND THE INDEX IS AN AVERAGE OF THE SHARE PRICES OF ALL THE COMPANIES.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(381, 'PRIMARY MARKET', ' PRIMARY MARKETS ARE WHEN INVESTORS ARE ABLE TO PURCHASE SECURITIES DIRECTLY FROM THE ISSUER.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(382, 'PRIVATE INVESTMENT FUND', ' PRIVATE INVESTMENT FUNDS ARE THOSE WHICH DO NOT SOLICIT PUBLIC INVESTMENT.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(383, 'PROFITS INTEREST', ' PROFITS INTEREST IS A WAY FOR PARTNERSHIPS TO REWARD AND RETAIN EMPLOYEES IN LIEU OF HAVING EQUITY TO GRANT.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(384, 'PROXY', ' A PROXY IS AN AGENT LEGALLY AUTHORIZED TO ACT ON BEHALF OF ANOTHER PARTY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(385, 'PUBLIC COMPANY', ' A PUBLIC COMPANY ISSUES SHARES THROUGH AN IPO AND TRADES ON AT LEAST ONE STOCK EXCHANGE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(386, 'PURCHASE PRICE', ' THE PURCHASE PRICE IS THE PRICE AN INVESTOR PAYS FOR AN INVESTMENT, AND THE PRICE BECOMES THE INVESTORS COST BASIS FOR CALCULATING GAIN OR LOSS WHEN SELLING THE INVESTMENT.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(387, 'Q', ' Q IS A FORMER NASDAQ DESIGNATION THAT NOTED A COMPANY HAD FILED FOR BANKRUPTCY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(388, 'QSEHRA', ' A QSEHRA IS A HEALTH COST REIMBURSEMENT PLAN THAT CAN BE OFFERED BY SMALL BUSINESS EMPLOYERS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(389, 'QTUM', ' QTUM IS A CRYPTOCURRENCY THAT COMBINES ETHEREUMS SMART CONTRACT FUNCTIONALITY WITH BITCOINS SECURITY TO CREATE A COIN THAT IS SUITABLE FOR ADOPTION BY LARGE ORGANIZATIONS. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(390, 'QUADRIX', '  QUADRIX IS A STOCK VALUATION SYSTEM THAT USES OVER 90 VARIABLES IN SEVEN MAJOR CATEGORIES TO DETERMINE THE VALUE OF A STOCK. THE QUADRIX SYSTEM IS PRODUCED AND MAINTAINED BY HORIZON PUBLISHING COMPANY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(391, 'QUALIFICATION RATIO', ' A QUALIFICATION RATIO NOTES THE PROPORTION OF EITHER DEBT TO INCOME OR HOUSING EXPENSE TO INCOME. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(392, 'QUALIFIED MORTGAGE', ' A QUALIFIED MORTGAGE IS A MORTGAGE THAT MEETS CERTAIN REQUIREMENTS FOR LENDER PROTECTION AND SECONDARY MARKET TRADING UNDER THE DODDFRANK WALL STREET REFORM AND CONSUMER PROTECTION ACT.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(393, 'QUALIFIED RETIREMENT PLAN', ' A QUALIFIED RETIREMENT PLAN MEETS IRS REQUIREMENTS AND OFFERS CERTAIN TAX BENEFITS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(394, 'QUALIFYING INVESTMENT', ' A QUALIFYING INVESTMENT REFERS TO AN INVESTMENT PURCHASED WITH PRETAX INCOME, USUALLY IN THE FORM OF A CONTRIBUTION TO A RETIREMENT PLAN.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(395, 'QUALIFYING RATIOS', ' QUALIFYING RATIOS ARE MEASURING DEVICES THAT BANKS AND OTHER FINANCIAL INSTITUTIONS USE IN THEIR LOAN UNDERWRITING PROCESS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(396, 'QUALIFYING RELATIVE', ' A QUALIFYING RELATIVE IS AN ALLOWANCE FOR A NONCHILD DEPENDENT OF A TAXPAYERS HOUSEHOLD TO BE CLAIMED AS A DEPENDENT FOR TAX PURPOSES.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(397, 'QUALIFYING TRANSACTION', ' A QUALIFYING TRANSACTION IS A TRANSACTION WHERE A CAPITAL POOL COMPANY (CPC) ACQUIRES SIGNIFICANT ASSETS, OTHER THAN CASH, SUCH AS A PRIVATE BUSINESS OR BUSINESSES.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(398, 'QUALITATIVE ANALYSIS', ' QUALITATIVE ANALYSIS USES SUBJECTIVE JUDGMENT BASED ON NONQUANTIFIABLE INFORMATION, SUCH AS MANAGEMENT EXPERTISE, INDUSTRY CYCLES, STRENGTH OF RESEARCH AND DEVELOPMENT AND LABOR RELATIONS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(399, 'QUALITY OF EARNINGS', '  A COMPANYS QUALITY OF EARNINGS IS REVEALED BY DISMISSING ANY ANOMALIES, ACCOUNTING TRICKS, OR ONETIME EVENTS THAT MAY SKEW THE REAL BOTTOMLINE NUMBERS ON PERFORMANCE. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(400, 'QUANT FUND', ' A QUANT FUND IS AN INVESTMENT FUND THAT SELECTS SECURITIES BY UTILIZING THE CAPABILITIES OF ADVANCED QUANTITATIVE ANALYSIS. IN QUANT FUNDS, MANAGERS BUILD CUSTOMIZED MODELS USING SOFTWARE PROGRAMS TO DETERMINE INVESTMENTS FOR THE FUND. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38');
INSERT INTO `mpx_fund_dictionary` (`fd_id`, `title`, `description`, `status`, `created_id`, `updated_id`, `created_at`, `updated_at`, `migration_at`) VALUES
(401, 'QUANTITATIVE ANALYSIS (QA)', ' QUANTITATIVE ANALYSIS (QA) IS A TECHNIQUE THAT SEEKS TO UNDERSTAND BEHAVIOR BY USING MATHEMATICAL AND STATISTICAL MODELING, MEASUREMENT, AND RESEARCH.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(402, 'QUANTITATIVE TRADING', ' QUANTITATIVE TRADING CONSISTS OF TRADING STRATEGIES BASED ON QUANTITATIVE ANALYSIS, WHICH RELY ON MATHEMATICAL COMPUTATIONS AND NUMBER CRUNCHING TO IDENTIFY TRADING OPPORTUNITIES.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(403, 'QUANTO SWAP', ' A QUANTO SWAP IS A CASHSETTLED, CROSSCURRENCY INTEREST RATE SWAP, WHERE ONE OF THE COUNTERPARTIES PAYS A FOREIGN INTEREST RATE TO THE OTHER.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(404, 'QUARTER (Q1, Q2, Q3, Q4)', ' A QUARTER IS A THREEMONTH PERIOD ON A COMPANYS FINANCIAL CALENDAR THAT ACTS AS A BASIS FOR PERIODIC FINANCIAL REPORTS AND THE PAYING OF DIVIDENDS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(405, 'QUARTER ON QUARTER (QOQ)', ' QOQ COMPARES A CHANGE IN PERFORMANCE BETWEEN ONE FISCAL QUARTER AND THE PREVIOUS FISCAL QUARTER.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(406, 'QUARTERLY REVENUE GROWTH', ' QUARTERLY REVENUE GROWTH MEASURES THE INCREASE IN A FIRMS SALES FROM ONE QUARTER TO ANOTHER.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(407, 'QUARTER-TO-DATE (QTD)', ' QUARTERTODATE (QTD) IS A TIME INTERVAL THAT CAPTURES ALL RELEVANT COMPANY ACTIVITY THAT OCCURRED BETWEEN THE BEGINNING OF THE CURRENT QUARTER AND THE POINT AT WHICH THE DATA WAS GATHERED. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(408, 'QUARTILE', ' A QUARTILE IS A STATISTICAL TERM DESCRIBING A DIVISION OF OBSERVATIONS INTO FOUR DEFINED INTERVALS BASED UPON THE VALUES OF THE DATA AND HOW THEY COMPARE TO THE ENTIRE SET OF OBSERVATIONS. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(409, 'QUASI CONTRACT', ' A QUASI CONTRACT IS A RETROACTIVE ARRANGEMENT BETWEEN TWO PARTIES WHO HAVE NO PREVIOUS OBLIGATIONS TO ONE ANOTHER.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(410, 'QUICK ASSETS', ' QUICK ASSETS REFER TO ASSETS OWNED BY A COMPANY WITH A COMMERCIAL OR EXCHANGE VALUE THAT CAN EASILY BE CONVERTED INTO CASH OR THAT ARE ALREADY IN A CASH FORM.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(411, 'QUICK LIQUIDITY RATIO', ' QUICK LIQUIDITY RATIO IS THE TOTAL AMOUNT OF A COMPANYS QUICK ASSETS DIVIDED BY THE SUM OF ITS NET LIABILITIES AND ITS REINSURANCE LIABILITIES.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(412, 'QUICK RATIO', ' THE QUICK RATIO INDICATES A COMPANYS CAPACITY TO PAY ITS CURRENT LIABILITIES WITHOUT NEEDING TO SELL ITS INVENTORY OR GET ADDITIONAL FINANCING.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(413, 'QUID', '  QUID IS WELLKNOWN, SLANG EXPRESSION FOR THE POUND STERLING, OR THE BRITISH POUND, WHICH IS THE CURRENCY OF THE UNITED KINGDOM. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(414, 'QUIET PERIOD', ' A QUIET PERIOD IS A SET AMOUNT OF TIME IN WHICH A COMPANYS MANAGEMENT AND MARKETING TEAMS CANNOT SHARE OPINIONS OR ADDITIONAL INFORMATION ABOUT THE FIRM.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(415, 'QUIET TITLE ACTION', ' A QUIET TITLE ACTION IS A LEGAL ACTION THAT IS INTENDED TO CLARIFY OWNERSHIP OF A GIVEN PROPERTY. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(416, 'QUINTILE', ' A QUINTILE IS A STATISTICAL VALUE OF A DATA SET THAT REPRESENTS 20 OF A GIVEN POPULATION, SO THE FIRST QUINTILE REPRESENTS THE LOWEST FIFTH OF THE DATA (1 TO 20) THE SECOND QUINTILE REPRESENTS THE SECOND FIFTH (21 TO 40) AND SO ON.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(417, 'QUOTA PERIOD', '  A QUOTA IS A GOVERNMENTIMPOSED TRADE RESTRICTION THAT LIMITS THE NUMBER OR MONETARY VALUE OF GOODS THAT A COUNTRY CAN IMPORT OR EXPORT DURING A PARTICULAR PERIOD. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(418, 'QUOTA SHARE TREATY', ' A QUOTA SHARE TREATY IS A PRORATA REINSURANCE CONTRACT IN WHICH THE INSURER AND REINSURER SHARE PREMIUMS AND LOSSES ACCORDING TO A FIXED PERCENTAGE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(419, 'QUOTATIONS', ' QUOTATIONS REFER TO THE MOST RECENT SALE PRICE A STOCK, BOND, OR ANY OTHER ASSET TRADED.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(420, 'QUOTE', ' A QUOTE IS THE LAST PRICE AT WHICH A SECURITY OR COMMODITY TRADED, MEANING THE MOST RECENT PRICE TO WHICH A BUYER AND SELLER AGREED AND AT WHICH SOME AMOUNT OF THE ASSET WAS TRANSACTED.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(421, 'QUOTE STUFFING', ' QUOTE STUFFING IS THE PRACTICE OF QUICKLY ENTERING AND THEN WITHDRAWING LARGE ORDERS IN AN ATTEMPT TO FLOOD THE MARKET WITH QUOTES, CAUSING COMPETITORS TO LOSE TIME IN PROCESSING THEM.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(422, 'QUOTED PRICE', ' A QUOTED PRICE IS THE MOST RECENT PRICE AT WHICH AN INVESTMENT (OR ANY OTHER TYPE OF ASSET) HAS TRADED.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(423, 'QUOTE-DRIVEN MARKET', '  A QUOTEDRIVEN MARKET IS AN ELECTRONIC STOCK EXCHANGE SYSTEM IN WHICH PRICES ARE DETERMINED FROM BID AND ASK QUOTATIONS MADE BY MARKET MAKERS, DEALERS, OR SPECIALISTS. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(424, 'R2', ' THE PERCENTAGE OF A FUNDS MOVEMENTS THAT RESULT FROM MOVEMENTS IN THE INDEX RANGING FROM 0 TO 100. A FUND WITH AN R2 OF 100 MEANS THAT 100 PERCENT OF THE FUNDS MOVEMENT CAN COMPLETELY BE EXPLAINED BY MOVEMENTS IN THE FUNDS EXTERNAL INDEX BENCHMARK.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(425, 'RALLY', ' A RALLY IS A PERIOD OF SUSTAINED INCREASES IN THE PRICES OF STOCKS, BONDS OR INDEXES.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(426, 'RATE OF RETURN (ROR)', '  THE RATE OF RETURN (ROR) IS USED TO MEASURE THE PROFIT OR LOSS OF AN INVESTMENT OVER TIME.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(427, 'RATING', ' A RATING IS AN ASSESSMENT TOOL ASSIGNED BY AN ANALYST OR RATING AGENCY TO A STOCK OR BOND. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(428, 'Rating Profile', ' Mutual funds invest in securities after evaluating their creditworthiness as disclosed by the ratings.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(429, 'REAL INTEREST RATE', ' THE REAL INTEREST RATE ADJUSTS THE OBSERVED MARKET INTEREST RATE FOR THE EFFECTS OF INFLATION.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(430, 'REAL RATE OF RETURN', ' THE REAL RATE OF RETURN ADJUSTS PROFIT FOR THE EFFECTS OF INFLATION.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(431, 'REAL TIME', ' REALTIME IS WHEN A SYSTEM RELAYS INFORMATION TO A USER AT A SPEED THAT IS NEARINSTANTANEOUS OR HAS A SHORT DELAY FROM WHEN THE EVENT OCCURRED.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(432, 'REALIZED GAIN', ' A REALIZED GAIN IS WHEN AN INVESTMENT IS SOLD FOR A HIGHER PRICE THAN WHERE IT WAS PURCHASED.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(433, 'REBALANCING', ' REBALANCING IS THE ACT OF ADJUSTING PORTFOLIO ASSET WEIGHTS IN ORDER TO RESTORE TARGET ALLOCATIONS OR RISK LEVELS OVER TIME.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(434, 'REBATE', ' A REBATE IS THE PORTION OF INTEREST OR DIVIDENDS EARNED BY THE OWNER (LENDER) OF A STOCK THAT IS PAID BY A SHORT SELLER (BORROWER) OF THE STOCK. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(435, 'RECESSION', ' A RECESSION IS A PERIOD OF DECLINING ECONOMIC PERFORMANCE ACROSS AN ENTIRE ECONOMY THAT LASTS FOR SEVERAL MONTHS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(436, 'RECORD DATE', ' THE RECORD DATE IS THE CUTOFF DATE USED TO DETERMINE WHICH SHAREHOLDERS ARE ENTITLED TO A CORPORATE DIVIDEND.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(437, 'REDEMPTION', ' IN FINANCE, REDEMPTION DESCRIBES THE REPAYMENT OF A FIXEDINCOME SECURITY SUCH AS A PREFERRED STOCK OR BOND ON OR BEFORE ITS MATURITY DATE. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(438, 'REGISTERED INVESTMENT ADVISOR (RIA)', '  A REGISTERED INVESTMENT ADVISOR (RIA) MANAGES THE ASSETS OF INDIVIDUAL AND INSTITUTIONAL INVESTORS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(439, 'REGISTERED REPRESENTATIVE (RR)', ' A REGISTERED REPRESENTATIVE (RR) IS A PERSON WHO WORKS FOR A BROKERAGE COMPANY AND SERVES AS A REPRESENTATIVE FOR CLIENTS TRADING INVESTMENT PRODUCTS SUCH AS STOCKS, BONDS, AND MUTUAL FUNDS. REGISTERED REPRESENTATIVES ARE ALSO KNOWN AS BROKERS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(440, 'REGULATION CC', ' REGULATION CC IMPLEMENTS THE EXPEDITED FUNDS AVAILABILITY ACT OF 1987.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(441, 'REINVESTMENT', ' REINVESTMENT IS WHEN INCOME DISTRIBUTIONS RECEIVED FROM AN INVESTMENT ARE PLOWED BACK INTO THAT INVESTMENT INSTEAD OF RECEIVING CASH.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(442, 'RELATIVE VALUE', ' RELATIVE VALUE LOOKS AT AN ASSETS WORTH BY COMPARING IT WITH THE VALUE OF SIMILAR ASSETS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(443, 'REPATRIATION', ' REPATRIATION REFERS TO CONVERTING ANY FOREIGN CURRENCY INTO ONES LOCAL CURRENCY. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(444, 'REPURCHASE AGREEMENT (REPO)', ' A REPURCHASE AGREEMENT, OR REPO, IS A SHORTTERM AGREEMENT TO SELL SECURITIES IN ORDER TO BUY THEM BACK AT A SLIGHTLY HIGHER PRICE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(445, 'REQUIRED RATE OF RETURN ГўвӮ¬вҖң RRR', ' THE REQUIRED RATE OF RETURN IS THE MINIMUM RETURN AN INVESTOR WILL ACCEPT FOR OWNING A COMPANYS STOCK, THAT COMPENSATES THEM FOR A GIVEN LEVEL OF RISK.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(446, 'RESERVE FUND', ' A RESERVE FUND IS A SAVINGS ACCOUNT OR OTHER HIGHLY LIQUID ASSET SET ASIDE BY AN INDIVIDUAL OR BUSINESS TO MEET ANY FUTURE COSTS OR FINANCIAL OBLIGATIONS, ESPECIALLY THOSE ARISING UNEXPECTEDLY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(447, 'RESERVE RATIO', ' THE RESERVE RATIO, SET BY THE FEDERAL RESERVE, IS THE PERCENTAGE OF A COMMERCIAL BANKS DEPOSITS THAT IT MUST KEEP IN CASH AS A RESERVE IN CASE OF MASS CUSTOMER WITHDRAWALS', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(448, 'RESIDUAL DIVIDEND', ' RESIDUAL DIVIDEND POLICIES ARE ADOPTED BY COMPANIES TO PRIORITIZE CAPITAL EXPENDITURES OVER IMMEDIATE SHAREHOLDER DIVIDEND PAYMENTS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(449, 'RESIDUAL SUM OF SQUARES (RSS)', ' A RESIDUAL SUM OF SQUARES (RSS) IS A STATISTICAL TECHNIQUE USED TO MEASURE THE AMOUNT OF VARIANCE IN A DATA SET THAT IS NOT EXPLAINED BY A REGRESSION MODEL.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(450, 'RESTRICTED STOCK', ' RESTRICTED STOCK IS A FORM OF EXECUTIVE COMPENSATION OFFERED BY CORPORATIONS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(451, 'RETAIL INVESTOR', ' RETAIL INVESTORS ARE NONPROFESSIONAL MARKET PARTICIPANTS WHO GENERALLY INVEST SMALLER AMOUNTS THAN LARGER, INSTITUTIONAL INVESTORS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(452, 'RETURN OF CAPITAL', ' RETURN OF CAPITAL (ROC) IS A PAYMENT, OR RETURN, RECEIVED FROM AN INVESTMENT THAT IS NOT CONSIDERED A TAXABLE EVENT AND IS NOT TAXED AS INCOME.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(453, 'RETURN ON INVESTED CAPITAL (ROIC)', ' ROIC IS THE AMOUNT OF RETURN A COMPANY MAKES ABOVE THE AVERAGE COST IT PAYS FOR ITS DEBT AND EQUITY CAPITAL.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(454, 'RISK MANAGEMENT', ' RISK MANAGEMENT IS THE PROCESS OF IDENTIFICATION, ANALYSIS AND ACCEPTANCE OR MITIGATION OF UNCERTAINTY IN INVESTMENT DECISIONS..', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(455, 'RISK MEASURES', ' RISK MEASURES ARE STATISTICAL MEASURES THAT ARE HISTORICAL PREDICTORS OF INVESTMENT RISK AND VOLATILITY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(456, 'RISK TOLERANCE', ' RISK TOLERANCE IS THE DEGREE OF VARIABILITY IN INVESTMENT RETURNS THAT AN INVESTOR IS WILLING TO WITHSTAND IN THEIR FINANCIAL PLANNING. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(457, 'RISK-NEUTRAL MEASURES', ' A RISK NEUTRAL MEASURE IS A PROBABILITY MEASURE USED IN MATHEMATICAL FINANCE TO AID IN PRICING DERIVATIVES AND OTHER FINANCIAL ASSETS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(458, 'RISK-ON RISK-OFF', ' RISKON RISKOFF IS AN INVESTMENT PARADIGM UNDER WHICH ASSET PRICES ARE DICTATED BY CHANGES IN INVESTORS RISK TOLERANCE', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(459, 'R-squared', ' This term is used to gauge the correlation between the mutual fund scheme and the benchmark index measured in the range of 0 to 100.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(460, 'RUSSELL 2000 INDEX', ' THE RUSSELL 2000 INDEX, CREATED IN 1984 BY THE FRANK RUSSELL COMPANY, IS A STOCK MARKET INDEX COMPRISED OF 2000 SMALLCAPITALIZATION COMPANIES.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(461, 'S&P 500 DIVIDEND ARISTOCRATS INDEX', ' THE SP 500 DIVIDEND ARISTOCRATS INDEX IS A LIST OF COMPANIES, MAINLY WELLKNOWN LARGECAP BLUECHIP COMPANIES, IN THE SP 500 WITH A TRACK RECORD OF INCREASING DIVIDENDS FOR AT LEAST 25 CONSECUTIVE YEARS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(462, 'SAFE HAVEN', ' SAFE HAVEN INVESTMENTS OFFER PROTECTION FROM MARKET DOWNSWINGS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(463, 'SALES AND PURCHASE AGREEMENT ГўвӮ¬вҖң SPA', ' A SALES AND PURCHASE AGREEMENT (SPA) IS A BINDING LEGAL CONTRACT THAT OBLIGATES A BUYER TO BUY AND A SELLER TO SELL A PRODUCT OR SERVICE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(464, 'SCENARIO ANALYSIS', ' SCENARIO ANALYSIS IS THE PROCESS OF ESTIMATING THE EXPECTED VALUE OF A PORTFOLIO AFTER A GIVEN PERIOD OF TIME, ASSUMING SPECIFIC CHANGES IN THE VALUES OF THE PORTFOLIOS SECURITIES OR KEY FACTORS TAKE PLACE, SUCH AS A CHANGE IN THE INTEREST RATE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(465, 'SECONDARY MARKET', ' IN SECONDARY MARKETS, INVESTORS EXCHANGE WITH EACH OTHER RATHER THAN WITH THE ISSUING ENTITY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(466, 'SECTOR BREAKDOWN', ' A SECTOR BREAKDOWN IS THE MIX OF SECTORS WITHIN A FUND OR PORTFOLIO, TYPICALLY EXPRESSED AS A PORTFOLIO PERCENTAGE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(467, 'Sector Fund', ' A fund that invests primarily in securities of companies engaged in a specific investment segment. Sector funds entail more risk, but may offer greater potential returns than funds that diversify their portfolios.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(468, 'SECULAR', ' SECULAR REFERS TO MARKET ACTIVITIES OVER THE LONG TERM OR A STOCK THAT ISNT INFLUENCED BY SHORTTERM FACTORS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(469, 'SECURITIES AND EXCHANGE BOARD OF INDIA (SEBI)', ' THE SECURITIES AND EXCHANGE BOARD OF INDIA (SEBI) IS THE LEADING REGULATOR SECURITIES MARKETS IN INDIA, ANALOGOUS TO THE SECURITIES AND EXCHANGE COMMISSION IN THE U.S.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(470, 'SECURITY', ' SECURITIES ARE FUNGIBLE AND TRADABLE FINANCIAL INSTRUMENTS USED TO RAISE CAPITAL IN PUBLIC AND PRIVATE MARKETS. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(471, 'SENSEX', ' BSE SENSEX REFERS TO THE BOMBAY STOCK EXCHANGES INDEX, WHICH WAS CREATED IN 1986 AND REPRESENTS 30 OF THE LARGEST AND MOST WELLCAPITALIZED STOCKS ON THE EXCHANGE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(472, 'SERIES I BOND', ' A SERIES I BOND IS A NONMARKETABLE, INTERESTBEARING U.S. GOVERNMENT SAVINGS BOND.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(473, 'SHARE CERTIFICATE', ' SHARE CERTIFICATES ARE DOCUMENTS ISSUED BY COMPANIES THAT SELL SHARES IN THE MARKET.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(474, 'SHAREHOLDER', ' A SHAREHOLDER, ALSO REFERRED TO AS A STOCKHOLDER, IS ANY PERSON, COMPANY, OR INSTITUTION THAT OWNS AT LEAST ONE SHARE OF A COMPANYS STOCK.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(475, 'SHAREHOLDER VALUE', ' SHAREHOLDER VALUE IS THAT VALUE GIVEN TO STOCKHOLDERS IN A COMPANY BASED ON THE FIRMS ABILITY TO SUSTAIN AND GROW PROFITS OVER TIME.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(476, 'SHARES', ' SHARES ARE UNITS OF OWNERSHIP INTEREST IN A CORPORATION OR FINANCIAL ASSET THAT PROVIDE FOR AN EQUAL DISTRIBUTION IN ANY PROFITS, IF ANY ARE DECLARED, IN THE FORM OF DIVIDENDS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(477, 'Sharpe Ratio', ' The Sharpe Ratio, named after its founder, the Nobel Laureate William Sharpe, is a measure of riskadjusted returns. This ratio measures the riskadjusted performance for each unit of dispersion measured by Standard Deviation.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(478, 'SHORT-TERM INVESTMENTS', ' SHORTTERM INVESTMENTS ARE MARKETABLE SECURITIES OR HIGHLY LIQUID ASSETS DESIGNED TO PROVIDE A SAFE, TEMPORARY PARKING PLACE FOR EXCESS CASH.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(479, 'SIMPLE INTEREST', '  SIMPLE INTEREST IS CALCULATED BY MULTIPLYING THE DAILY INTEREST RATE BY THE PRINCIPAL, BY THE NUMBER OF DAYS THAT ELAPSE BETWEEN PAYMENTS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(480, 'SINKING FUND', ' A SINKING FUND IS AN ACCOUNT CONTAINING MONEY SET ASIDE TO PAY OFF A DEBT OR BOND.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(481, 'SIP', ' SIP or systematic investment plan works on the principle of making periodic investments of a fixed sum.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(482, 'SMALL CAP', ' A SMALL CAP IS GENERALLY A COMPANY WITH A MARKET CAPITALIZATION OF BETWEEN 300 MILLION AND 2 BILLION.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(483, 'SMART MONEY', ' SMART MONEY IS CAPITAL PLACED IN THE MARKET BY INSTITUTIONAL INVESTORS, MARKET MAVENS, CENTRAL BANKS, FUNDS, AND OTHER FINANCIAL PROFESSIONALS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(484, 'STABLE VALUE FUND', ' A STABLE VALUE FUND IS AN INSURED BOND PORTFOLIO.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(485, 'STAKEHOLDER', ' A STAKEHOLDER IS A PARTY THAT HAS AN INTEREST IN A COMPANY AND CAN EITHER AFFECT OR BE AFFECTED BY THE BUSINESS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(486, 'Standard Deviation', ' Standard deviation is a statistical measure of the range of an investments performance. It implies how much returns on a fund are deviating from the average returns based on its historical performance.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(487, 'STOCK', ' A STOCK IS A FORM OF SECURITY THAT INDICATES THE HOLDER HAS PROPORTIONATE OWNERSHIP IN THE ISSUING CORPORATION.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(488, 'STOCK APPRECIATION RIGHT (SAR)', ' STOCK APPRECIATION RIGHTS (SARS) ARE A FORM OF COMPENSATION, OFTEN RECEIVED AS A BONUS, THAT AWARDS THE CASH VALUE EQUIVALENT TO THE CHANGE IN A COMPANYS STOCK OVER SOME VESTING PERIOD.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(489, 'STOCK DIVIDEND', ' A STOCK DIVIDEND IS A DIVIDEND PAID TO SHAREHOLDERS IN THE FORM OF ADDITIONAL SHARES IN THE COMPANY, RATHER THAN AS CASH.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(490, 'STOCK EXCHANGE DAILY OFFICIAL LIST (SEDOL)', ' SEDOL CODES ARE UNIQUE SEVENCHARACTER ALPHANUMERIC IDENTIFIERS ASSIGNED TO SECURITIES THAT TRADE ON THE LONDON STOCK EXCHANGE AND OTHER SMALLER EXCHANGES IN THE UNITED KINGDOM.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(491, 'STOCK MARKET', ' STOCK MARKETS ARE VITAL COMPONENTS OF A FREEMARKET ECONOMY BECAUSE THEY ENABLE DEMOCRATIZED ACCESS TO TRADING AND EXCHANGE OF CAPITAL FOR INVESTORS OF ALL KINDS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(492, 'STOCK MARKET CRASH', ' STOCK MARKET CRASHES ARE AN ABRUPT DOUBLEDIGIT DROP IN STOCK PRICES.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(493, 'SYSTEMATIC INVESTMENT PLAN (SIP)', ' It gives investors the liberty to invest in a scheme on a monthly basis like a bank recurring deposits. Every month fresh units are bought with the monthly payments of the investor at prevailing NAV of the day at the date chosen by the investor.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(494, 'Systematic transfer plan (STP)', ' Systematic transfer plan allows investors to transfer the predefined amount on a specified date from one particular scheme to another by giving onetime instruction to the fund house.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(495, 'Systematic withdrawal plan (SWP)', ' Systematic withdrawal plan helps investors to redeem a fixed amount of their investments from their mutual funds.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(496, 'T+1 (T+2,T+3)', ' T1 (T2, T3) REFERS TO THE SETTLEMENT DATE OF TRANSACTIONS. T REFERS TO THE TRANSACTION DATE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(497, 'TARGET-DATE FUND', ' A TARGETDATE FUND IS A FUND IS A CLASS OF MUTUAL FUNDS THAT REBALANCES ASSET CLASS WEIGHTS OVER TIME SO THAT IT BEGINS HEAVIER TO STOCKS WHEN YOU ARE YOUNGER AND HEAVIER TO BONDS AS YOU AGE. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(498, 'TERM SHEET', ' A TERM SHEET IS A NONBINDING AGREEMENT SETTING FORTH THE BASIC TERMS AND CONDITIONS UNDER WHICH AN INVESTMENT WILL BE MADE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(499, 'TERMINAL VALUE (TV)', ' TERMINAL VALUE (TV) DETERMINES A COMPANYS VALUE INTO PERPETUITY BEYOND A SET FORECAST PERIODUSUALLY FIVE YEARS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(500, 'THEORETICAL EX-RIGHTS PRICE ГўвӮ¬вҖң TERP', ' TERP IS A THEORETICAL MARKET PRICE AFTER A RIGHTS OFFERING.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(501, 'THIRD PARTY', ' A THIRD PARTY IS AN INDIVIDUAL OR ENTITY THAT IS INVOLVED IN A TRANSACTION BUT IS NOT ONE OF THE PRINCIPALS AND HAS A LESSER INTEREST. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(502, 'TIME HORIZON', '  TIME HORIZONS ARE PERIODS WHERE INVESTMENTS ARE HELD UNTIL THEY ARE NEEDED.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(503, 'TIMES INTEREST EARNED (TIE) RATIO', ' A COMPANYS TIE INDICATES ITS ABILITY TO PAY ITS DEBTS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(504, 'TIME-WEIGHTED RATE OF RETURN ГўвӮ¬вҖң TWR', ' THE TIMEWEIGHTED RETURN (TWR) MULTIPLIES THE RETURNS FOR EACH SUBPERIOD OR HOLDINGPERIOD, WHICH LINKS THEM TOGETHER SHOWING HOW THE RETURNS ARE COMPOUNDED OVER TIME. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(505, 'TOP 10 HOLDINGS', ' TEN LARGEST HOLDINGS IN A PORTFOLIO BASED ON ASSET VALUE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(506, 'TOP 10 LONG AND SHORT POSITIONS', ' THE TOP 10 HOLDINGS RANKED BY MARKET VALUE IN EACH POSITION CATEGORY (LONG AND SHORT). A LONG POSITION IS ONE IN WHICH AN INVESTOR BUYS SHARES OF STOCK AND AS AN EQUITY HOLDER WILL PROFIT IF THE PRICE OF THE STOCK RISES. WITH A SHORT POSITION AN INVESTOR WILL SELL SHARES OF STOCK THAT THEY DO NOT OWN BUT HAVE BORROWED. THE INVESTOR IN A SHORT POSITION WILL PROFIT IF THE PRICE OF THE STOCK FALLS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(507, 'TOP FIVE CONTRIBUTORS', ' TOP FIVE INDUSTRIES IN A PORTFOLIO BASED ON AMOUNT OF INVESTED ASSETS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(508, 'TOP FIVE DETRACTORS', ' FIVE ASSETS IN A PORTFOLIO THAT GENERATED LARGEST NEGATIVE RETURNS (LOSSES).', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(509, 'TOP FIVE HOLDINGS', ' TOP FIVE SECURITIES IN A PORTFOLIO BASED ON AMOUNT OF INVESTED ASSETS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(510, 'TOP FIVE INDUSTRIES', ' TOP FIVE INDUSTRIES IN A PORTFOLIO BASED ON AMOUNT OF INVESTED ASSETS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(511, 'TOP-DOWN INVESTING', ' TOPDOWN INVESTING IS AN INVESTMENT ANALYSIS APPROACH THAT INVOLVES LOOKING FIRST AT THE MACRO PICTURE OF THE ECONOMY, AND THEN LOOKING AT THE SMALLER FACTORS IN FINER DETAIL.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(512, 'TOTAL BOND FUND', ' A TOTAL BOND FUND TRACKS THE PERFORMANCE OF ITS UNDERLYING INDEX, WHICH IN TURN MONITORS THE ENTIRE BOND MARKET.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(513, 'Total Expense Ratio (TER)', ' Apart from risks and returns, investors must look at the costs involved while investing in mutual funds.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(514, 'TOTAL RETURN', ' ACCOUNTS FOR ALL OF THE DIVIDENDS AND INTEREST EARNED BEFORE DEDUCTIONS FOR FEES AND EXPENSES, IN ADDITION TO ANY CHANGES IN THE VALUE OF THE PRINCIPAL, INCLUDING SHARE PRICE, ASSUMING THE FUNDS DIVIDENDS AND CAPITAL GAINS ARE REINVESTED. OFTEN, THIS PERCENTAGE IS PRESENTED IN A SPECIFIED PERIOD OF TIME (ONE, FIVE, TEN YEARS ANDOR LIFE OF FUND). ALSO, A METHOD OF CALCULATING AN INVESTMENTS RETURN THAT TAKES SHARE PRICE CHANGES AND DIVIDENDS INTO ACCOUNT.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(515, 'TOTAL RETURN INDEX', ' THE TOTAL RETURN INDEX IS A TYPE OF EQUITY INDEX THAT TRACKS BOTH THE CAPITAL GAINS OF A GROUP OF STOCKS OVER TIME, AND ASSUMES THAT ANY CASH DISTRIBUTIONS, SUCH AS DIVIDENDS, ARE REINVESTED BACK INTO THE INDEX. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(516, 'TRACKER FUND', ' TRACKER FUNDS ARE INDEX FUNDS USED TO TRACK A BROAD MARKET INDEX OR A SEGMENT OF ONE THEY ARE ALSO KNOWN AS INDEX FUNDS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(517, 'TRACKING ERROR', ' THE ACTIVE RISK OF THE PORTFOLIO. IT DETERMINES THE ANNUALIZED STANDARD DEVIATION OF THE EXCESS RETURNS BETWEEN THE PORTFOLIO AND THE BENCHMARK.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(518, 'TRACKING STOCK', ' A TRACKING STOCK IS AN EQUITY ISSUED BY A PARENT COMPANY THAT TRACKS THE FINANCIAL PERFORMANCE OF A PARTICULAR DIVISION.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(519, 'TRAILING PRICE-TO-EARNINGS (TRAILING P/E)', ' THE TRAILING PRICETOEARNINGS RATIO IS A RELATIVE VALUATION MULTIPLE BASED ON THE LAST 12 MONTHS OF ACTUAL EARNINGS, CALCULATED BY DIVIDING THE CURRENT STOCK PRICE BY THE TRAILING EPS FOR THE PREVIOUS YEAR.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(520, 'TRANSFER AGENT', ' AN AGENT, USUALLY A COMMERCIAL BANK, APPOINTED TO MONITOR RECORDS OF STOCKS, BONDS AND SHAREHOLDERS. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(521, 'TREASURY BILL', ' NEGOTIABLE SHORTTERM (ONE YEAR OR LESS) DEBT OBLIGATIONS ISSUED BY THE U.S. GOVERNMENT AND BACKED BY ITS FULL FAITH AND CREDIT.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(522, 'TREASURY BOND', ' NEGOTIABLE LONGTERM (10 YEARS OR LONGER) DEBT OBLIGATIONS ISSUED BY THE U.S. GOVERNMENT AND BACKED BY ITS FULL FAITH AND CREDIT.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(523, 'TREASURY NOTE', ' NEGOTIABLE MEDIUMTERM (ONE YEAR TO 10 YEARS) DEBT OBLIGATIONS ISSUED BY THE U.S. GOVERNMENT AND BACKED BY ITS FULL FAITH AND CREDIT.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(524, 'TREASURY SECURITY', ' SECURITIES ISSUED BY THE U.S. TREASURY DEPARTMENT AND BACKED BY THE U.S. GOVERNMEN', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(525, 'Treynor Ratio', ' A variant of the Sharpe Ratio, this measures the riskadjusted performance for each unit of dispersion measured by beta (i.e. market risk).', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(526, 'Trigger Facility', ' Mutual funds offer an optional feature that gets automatically activated (through an alert) on the occurrence of a predefined event.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(527, 'Trustee', ' Legal custodian who looks after all the monies invested in a unit trust or mutual fund.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(528, 'ULTRA ETF', ' ULTRA ETFS ARE A CLASS OF EXCHANGETRADED FUND (ETF) THAT EMPLOYS LEVERAGE IN AN EFFORT TO ACHIEVE DOUBLE THE RETURN OF A SET BENCHMARK. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(529, 'ULTRA-SHORT BOND FUND', ' ULTRASHORT FUNDS HAVE MORE FREEDOM AND TYPICALLY PURSUE HIGHER YIELDS BY INVESTING IN RISKIER SECURITIES.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(530, 'UNCONSTRAINED INVESTING', ' UNCONSTRAINED INVESTING IS AN INVESTMENT STYLE THAT DOES NOT REQUIRE A FUND OR PORTFOLIO MANAGER TO ADHERE TO A SPECIFIC BENCHMARK.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(531, 'UNDERSUBSCRIBED', ' UNDERSUBSCRIBED (UNDERBOOKED) REFERS TO AN ISSUE OF SECURITIES WHERE DEMAND DOES NOT MEET THE AVAILABLE SUPPLY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(532, 'UNDERWEIGHT', ' UNDERWEIGHT REFERS TO ONE OF TWO SITUATIONS IN REGARD TO TRADING AND FINANCE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(533, 'Underwriter', ' One who does underwriting. A financial organization that handles sales of new securities which a company or municipality wishes to sell in order to raise money.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(534, 'UNITHOLDER', ' A UNITHOLDER IS AN INVESTOR WHO OWNS UNITS IN AN INVESTMENT TRUST OR MASTER LIMITED PARTNERSHIP (MLP).', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(535, 'UNITIZED FUND', ' A UNITIZED FUND IS A WAY TO POOL ASSETS FROM SEVERAL INVESTORS OFTEN IN A FOCUSED INVESTMENT SUCH AS A SINGLE STOCK.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(536, 'UNPAID DIVIDEND', ' UNPAID DIVIDENDS EXIST BECAUSE THERE IS A DIFFERENCE BETWEEN THE TIME WHEN A COMPANY ANNOUNCES ITS DIVIDEND AND THE TIME WHEN THAT DIVIDEND IS PAID.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(537, 'UNSUITABLE INVESTMENT (UNSUITABILITY)', ' AN UNSUITABLE INVESTMENT IS WHEN AN INVESTMENT SUCH AS A STOCK OR BONDDOES NOT MEET THE OBJECTIVES AND MEANS OF AN INVESTOR.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(538, 'UNWEIGHTED INDEX', ' AN UNWEIGHTED INDEX GIVES EQUAL ALLOCATION TO ALL SECURITIES WITHIN THE INDEX.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(539, 'UP-MARKET CAPTURE RATIO', ' THE UPMARKET CAPTURE RATIO IS THE STATISTICAL MEASURE OF AN INVESTMENT MANAGERS OVERALL PERFORMANCE IN UPMARKETS. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(540, 'UPPER MANAGEMENT', ' UPPER MANAGEMENT INCLUDES INDIVIDUALS AND TEAMS THAT ARE RESPONSIBLE FOR MAKING THE PRIMARY DECISIONS WITHIN A COMPANY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(541, 'UPSTAIRS MARKET', ' AN UPSTAIRS MARKET DESCRIBES THE TRADING OF SECURITIES, SUCH AS STOCKS, THAT OCCURS WITHIN A BROKERDEALER FIRM INSTEAD OF AT AN EXCHANGE, SUCH AS A STOCK EXCHANGE, OR BETWEEN TWO BROKERDEALERS IN THE OVERTHECOUNTER (OTC) MARKET.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(542, 'U-SHAPED RECOVERY', ' A USHAPED RECOVERY REPRESENTS THE SHAPE OF THE CHART OF CERTAIN ECONOMIC MEASURES, SUCH AS EMPLOYMENT, GDP AND INDUSTRIAL OUTPUT.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(543, 'UTILITIES INDUSTRY ETF', ' A UTILITIES INDUSTRY ETF IS AN EXCHANGETRADED FUND THAT INVESTS IN COMPANIES THAT GENERATE AND DISTRIBUTE ELECTRIC POWER.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(544, 'VALUATION', ' VALUATION IS THE ANALYTICAL PROCESS OF DETERMINING THE CURRENT (OR PROJECTED) WORTH OF AN ASSET OR A COMPANY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(545, 'VALUE', ' VALUE IS THE MONETARY, MATERIAL, OR ASSESSED WORTH OF AN ASSET, GOOD, OR SERVICE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(546, 'VALUE FUND', ' A VALUE FUND FOLLOWS A STRATEGY THAT FOCUSES ON INVESTING IN STOCKS THAT ARE UNDERVALUED IN PRICE BASED ON FUNDAMENTAL CHARACTERISTICS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(547, 'VALUE INVESTING', ' VALUE INVESTING IS AN INVESTMENT STRATEGY THAT INVOLVES PICKING STOCKS THAT APPEAR TO BE TRADING FOR LESS THAN THEIR INTRINSIC OR BOOK VALUE.5.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(548, 'VALUE STOCK', ' COMMON CHARACTERISTICS OF VALUE STOCKS INCLUDE HIGH DIVIDEND YIELD, LOW PB RATIO ANDOR A LOW PE RATIO.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(549, 'VALUE-STYLE FUNDS', ' VALUESTYLE FUNDS TYPICALLY HOLD COMPANY STOCKS THAT ARE UNDERVALUED IN THE MARKET. FUNDAMENTALLY STRONG COMPANIES WHOSE STOCKS ARE INEXPENSIVE BUT TRENDING UPWARD MAY ALSO BE SELECTED FOR VALUE FUNDS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(550, 'VANCOUVER STOCK EXCHANGE (VAN) .V', ' THE VANCOUVER STOCK EXCHANGE (VAN) .V  (VSE) IS A DEFUNCT STOCK EXCHANGE FORMERLY LOCATED IN VANCOUVER, BRITISH COLUMBIA', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(551, 'VANILLA STRATEGY', ' A VANILLA STRATEGY IS A COMMON OR POPULAR APPROACH TO INVESTING OR DECISION MAKING IN BUSINESS. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(552, 'VARIABLE COST RATIO', ' THE VARIABLE COST RATIO INDICATES THE ADDITIONAL COSTS THAT ARE INCURRED IN INCREASING PRODUCTION.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(553, 'VICE FUND', ' THE VICE FUND IS A MUTUAL FUND MANAGED BY USA MUTUALS WHICH FOCUSES ITS INVESTMENTS ON VICE INDUSTRIES CONSIDERED BY MANY TO BE SOCIALLY IRRESPONSIBLE INVESTMENTS OR SIN STOCKS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(554, 'VOLATILITY', ' THE AMOUNT AND FREQUENCY WITH WHICH AN INVESTMENT FLUCTUATES IN VALUE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(555, 'VOLATILITY INDEX (VXN) CBOE NASDAQ', ' THE CBOE NASDAQ VOLATILITY INDEX (VXN) IS A MEASURE OF MARKET EXPECTATIONS OF 30DAY VOLATILITY .', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(556, 'VULTURE FUND', ' A VULTURE FUND INVESTS IN ASSETS WHOSE PRICES HAVE BEEN SEVERELY DEPRESSED IN THE MARKET.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(557, 'WARSAW STOCK EXCHANGE (WSE)', ' THE WARSAW STOCK EXCHANGE (WSE) IS THE LARGEST STOCK EXCHANGE IN EASTERN EUROPE AND ONE OF THE MOST RECOGNIZED POLISH FINANCIAL INSTITUTIONS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(558, 'WASH SALE', ' A WASH SALE OCCURS WHEN AN INVESTOR SELLS A SECURITY AT A LOSS FOR TAX BENEFITS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(559, 'WATER ETF', ' THE WATER ETF IS AN EXCHANGETRADED FUND THAT INVESTS PRIMARILY IN COMPANIES THAT OPERATE WITHIN THE PURVIEW OF WATER TREATMENT, DISTRIBUTION AND SALES.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(560, 'WEIGHTED', ' WEIGHTED IS A DESCRIPTION OF ADJUSTMENTS TO A FIGURE TO REFLECT DIFFERENT PROPORTIONS OR WEIGHTS OF COMPONENTS THAT MAKE UP THAT FIGURE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(561, 'WEIGHTED AVERAGE MARKET CAP', ' MOST INDEXES ARE CONSTRUCTED BY WEIGHTING THE MARKET CAPITALIZATION OF EACH STOCK ON THE INDEX. IN SUCH AN INDEX, LARGER COMPANIES ACCOUNT FOR A GREATER PORTION OF THE INDEX. AN EXAMPLE IS THE SP 500 INDEX.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(562, 'WEIGHTED AVERAGE MATURITY', ' A FUNDS WAM CALCULATES AN AVERAGE TIME TO MATURITY OF ALL THE SECURITIES HELD IN THE PORTFOLIO, WEIGHTED BY EACH SECURITYS PERCENTAGE OF NET ASSETS. THE CALCULATION TAKES INTO ACCOUNT THE FINAL MATURITY FOR A FIXED INCOME SECURITY AND THE INTEREST RATE RESET DATE FOR FLOATING RATE SECURITIES HELD IN THE PORTFOLIO.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(563, 'WEIGHTED AVERAGE RATING FACTOR (WARF)', ' THE WEIGHTED AVERAGE RATING FACTOR (WARF) IS A MEASURE THAT IS USED BY CREDIT RATING COMPANIES TO INDICATE THE CREDIT QUALITY OF A PORTFOLIO.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(564, 'WHEN ISSUED ГўвӮ¬вҖң WI', ' WHEN ISSUED (WI) IS A TRANSACTION THAT IS MADE CONDITIONALLY BECAUSE A SECURITY HAS BEEN AUTHORIZED BUT NOT YET ISSUED.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(565, 'WHITE ELEPHANT', ' A WHITE ELEPHANT IS A BURDENSOME POSSESSION WHOSE COST OF UPKEEP IS NOT IN LINE WITH ITS USEFULNESS OR VALUE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(566, 'WIN/LOSS RATIO', ' THE WINLOSS OR SUCCESS RATIO IS A TRADERS NUMBER OF WINNING TRADES RELATIVE TO THE NUMBER OF LOSING TRADES.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(567, 'WIREHOUSE BROKER', ' A WIREHOUSE BROKER IS A NONINDEPENDENT BROKER WORKING FOR A WIREHOUSE FIRM, OR A FIRM WITH MULTIPLE BRANCHES SUCH AS A NATIONAL BROKERAGE HOUSE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(568, 'WORLD EQUITY BENCHMARK SERIES (WEBS)', ' THE WORLD EQUITY BENCHMARK SERIES IS A TYPE OF INTERNATIONAL FUND TRADED ON THE AMERICAN STOCK EXCHANGE. THE WORLD EQUITY BENCHMARK SERIES FOLLOWS THE MORGAN STANLEY CAPITAL INTERNATIONAL (MSCI) COUNTRY INDICES.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(569, 'WORLD FEDERATION OF STOCK EXCHANGES', ' THE WORLD FEDERATION OF STOCK EXCHANGES, MORE COMMONLY KNOWN AS THE WORLD FEDERATION OF EXCHANGES, IS AN INTERNATIONAL TRADE GROUP THAT SUPPORTS THE INTERESTS OF REGULATED SECURITIES EXCHANGES AROUND THE WORLD, AND PROMOTES WIDESPREAD ACCESS TO FINANCIAL MARKETS AND THE SAFETY AND SOUNDNESS OF THE GLOBAL FINANCIAL SYSTEM.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(570, 'WORLD FUND', ' A WORLD FUND IS A TYPE OF MUTUAL FUND THAT INVESTS IN SECURITIES FROM SEVERAL DIFFERENT COUNTRIES, INCLUDING THE UNITED STATES.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(571, 'XD', ' XD IS A SYMBOL THAT APPEARS AS A FOOTNOTE, SUBSCRIPT, SUPERSCRIPT, OR SUFFIX TO A TICKER SYMBOL ON A TRADING PLATFORM OR TIMELY PUBLISHED REPORT.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(572, 'XETRA', ' XETRA IS AN ALLELECTRONIC TRADING SYSTEM, BASED IN FRANKFURT, GERMANY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(573, 'YANKEE MARKET', ' YANKEE MARKET IS A SLANG TERM FOR THE STOCK MARKET IN THE UNITED STATES.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(574, 'YEAR TO DATE (YTD)', ' YTD REFERS TO A PERIOD OF TIME BEGINNING THE FIRST DAY OF THE CURRENT CALENDAR YEAR OR FISCAL YEAR UP TO THE CURRENT DATE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(575, 'YEN ETF', ' A YEN ETF IS A TYPE OF EXCHANGETRADED FUND (ETF) THAT INVESTS PRIMARILY IN SEVERAL TYPES OF YENBACKED ASSETS. CURRENCY ETFS, SUCH AS YEN ETFS, TRACK THE WAY ONE CURRENCY PERFORMS IN THE FOREIGN EXCHANGE MARKET AGAINST A BASKET OF CURRENCIES OR A SINGLE CURRENCY SUCH AS THE U.S. DOLLAR.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(576, 'YIELD', ' YIELD IS A RETURN MEASURE FOR AN INVESTMENT OVER A SET PERIOD OF TIME, EXPRESSED AS A PERCENTAGE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(577, 'YIELD CURVE', ' YIELD CURVES PLOT INTEREST RATES OF BONDS OF EQUAL CREDIT AND DIFFERENT MATURITIES.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(578, 'YIELD MAINTENANCE', ' YIELD MAINTENANCE IS A KIND OF PREPAYMENT FEE THAT BORROWERS PAY TO LENDERS, OR BOND ISSUERS TO INVESTORS, TO COMPENSATE FOR THE LOSS OF INTEREST RESULTING FROM THE PREPAYMENT OF A LOAN OR THE CALLING IN OF A BOND.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(579, 'YIELD TILT INDEX FUND', ' A YIELD TILT INDEX FUND IS A TYPE OF MUTUAL FUND THAT ALLOCATES CAPITAL AS A STANDARD INDEX, BUT WITH A WEIGHTED COMPONENT.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(580, 'Yield to Maturity', ' The Yield to Maturity or the YTM is the rate of return anticipated on a bond if held until maturity.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(581, 'YIELD TO MATURITY (YTM)', ' YIELD TO MATURITY (YTM) IS THE TOTAL RETURN ANTICIPATED ON A BOND IF THE BOND IS HELD UNTIL IT MATURES. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(582, 'YIELD TO MATURITY DISTRIBUTION', ' THE AVERAGE RATE OF RETURN THAT WILL BE EARNED ON A BOND IF HELD TO MATURITY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(583, 'YO-YO', ' YOYO IS SLANG FOR A VERY VOLATILE MARKET.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(584, 'Y-SHARE', ' YSHARES ARE AN INSTITUTIONAL SHARE CLASS OFFERED IN OPENEND MUTUAL FUNDS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(585, 'YUGEN KAISHA (YK)', ' YUGEN KAISHA (YKA) IS A TYPE OF LIMITED LIABILITY COMPANY THAT COULD BE ESTABLISHED IN JAPAN FROM 1940 THROUGH EARLY 2006.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(586, 'ZACKS INVESTMENT RESEARCH', ' ZACKS INVESTMENT RESEARCH IS AN AMERICAN COMPANY DEDICATED TO THE PRODUCTION OF INDEPENDENT RESEARCH AND INVESTMENTRELATED CONTENT.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(587, 'ZCASH', ' ZCASH IS A CRYPTOCURRENCY WITH A DECENTRALIZED BLOCKCHAIN THAT PROVIDES ANONYMITY FOR ITS USERS AND THEIR TRANSACTIONS.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(588, 'ZERO BALANCE ACCOUNT (ZBA)', ' A ZERO BALANCE ACCOUNT (ZBA) IS AN ACCOUNT IN WHICH A BALANCE OF ZERO IS MAINTAINED BY TRANSFERRING FUNDS TO AND FROM A MASTER ACCOUNT.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(589, 'ZERO COST COLLAR STRATEGY', ' A ZERO COST COLLAR STRATEGY IS USED TO HEDGE AGAINST VOLATILITY IN AN UNDERLYING ASSETS PRICES THROUGH THE PURCHASE OF CALL AND PUT OPTIONS THAT PLACE A CAP AND FLOOR ON PROFITS AND LOSSES FOR THE DERIVATIVE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(590, 'ZERO COUPON SWAP', ' A ZERO COUPON SWAP IS AN EXCHANGE OF FIXEDFORFLOATING CASH FLOWS, BUT WHERE THE FIXED SIDE OF THE SWAP IS PAID AS ONE LUMP SUM WHEN THE CONTRACT REACHES MATURITY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(591, 'ZERO-BASED BUDGETING (ZBB)', ' ZEROBASED BUDGETING (ZBB) IS A METHOD OF BUDGETING IN WHICH ALL EXPENSES MUST BE JUSTIFIED FOR EACH NEW PERIOD.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(592, 'ZERO-BETA', ' A ZEROBETA PORTFOLIO IS A PORTFOLIO CONSTRUCTED TO HAVE ZERO SYSTEMATIC RISK, OR IN OTHER WORDS, A BETA OF ZERO. A ZEROBETA PORTFOLIO WOULD HAVE THE SAME EXPECTED RETURN AS THE RISKFREE RATE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(593, 'ZERO-BOUND', ' ZEROBOUND IS AN EXPANSIONARY MONETARY POLICY TOOL WHERE A CENTRAL BANK LOWERS SHORT TERM INTEREST RATES TO ZERO, IF NEEDED, TO STIMULATE THE ECONOMY.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(594, 'ZERO-COUPON BOND', ' A ZEROCOUPON BOND IS A DEBT SECURITY THAT DOES NOT PAY INTEREST BUT INSTEAD TRADES AT A DEEP DISCOUNT, RENDERING A PROFIT AT MATURITY, WHEN THE BOND IS REDEEMED FOR ITS FULL FACE VALUE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(595, 'ZERO-COUPON INFLATION SWAP', ' IN A ZEROCOUPON INFLATION SWAP, WHICH IS A BASIC TYPE OF INFLATION DERIVATIVE, AN INCOME STREAM THAT IS TIED TO THE RATE OF INFLATION IS EXCHANGED FOR AN INCOME STREAM WITH A FIXED INTEREST RATE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(596, 'ZERO-INVESTMENT PORTFOLIO', ' A ZEROINVESTMENT PORTFOLIO IS A COLLECTION OF INVESTMENTS THAT HAS A NET VALUE OF ZERO WHEN THE PORTFOLIO IS ASSEMBLED, AND THEREFORE REQUIRES AN INVESTOR TO TAKE NO EQUITY STAKE IN THE PORTFOLIO.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(597, 'ZOMBIE ETF', ' A ZOMBIE ETF REFERS TO EXCHANGE TRADED FUNDS THAT ARE SEEING LITTLE TRADING VOLUME OR INCREASED INVESTMENT.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(598, 'Z-SCORE', ' A ZSCORE IS A NUMERICAL MEASUREMENT USED IN STATISTICS OF A VALUES RELATIONSHIP TO THE MEAN (AVERAGE) OF A GROUP OF VALUES, MEASURED IN TERMS OF STANDARD DEVIATIONS FROM THE MEAN.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(599, 'Z-TEST', ' A ZTEST IS A STATISTICAL TEST USED TO DETERMINE WHETHER TWO POPULATION MEANS ARE DIFFERENT WHEN THE VARIANCES ARE KNOWN AND THE SAMPLE SIZE IS LARGE.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(600, 'Emerging Market Economy', 'An emerging market economy is the economy of a developing nation that is becoming more engaged with global markets as it grows.   ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(601, 'Emerging Markets Bond Index (EMBI)', 'The emerging markets bond index (EMBI) tracks the performance of emerging market bonds and was first published by investment bank JP Morgan.  ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(602, 'Emerging Markets Index (MSCI)', 'The MSCI Emerging Markets Index is used to measureequity market performance in global emerging markets. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(603, 'Employer Identification Number (EIN)', 'An Employer Identification Number is a unique number assigned to a business so that it can easily be identified by the Internal Revenue Service (IRS).  ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38');
INSERT INTO `mpx_fund_dictionary` (`fd_id`, `title`, `description`, `status`, `created_id`, `updated_id`, `created_at`, `updated_at`, `migration_at`) VALUES
(604, 'Energy Return on Investment (EROI)', 'Energy Return on Investment (EROI) is the amount of energy expended to produce a certain amount of energy. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(605, 'Entry Load', 'A mutual fund may have a sales charge or load at the time of entry andor exit to compensate the distributoragent. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(606, 'Equal Weight', ' Equal weight is a type of weighting that gives the same weight, or importance, to each stock in a portfolio or index fund, and the smallest companies are given equal weight to the largest companies in an equalweight index fund or portfolio. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(607, 'Equities', 'The ownership interest in a company of holders of its common and preferred stock. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(608, 'Equity', ' There are various types of equity, but equity typically refers to shareholder equity, which represents the amount of money that would be returned to a companys shareholders if all of the assets were liquidated and all of the companys debt was paid off. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(609, 'Equity Capital Market (ECM)', ' Equity Capital Markets (ECM) refers to a broad network of financial institutions, channels, and markets that together assist companies to raise capital ECM consists of two types of markets primary equity markets, a place for raising money from private placement and the primary public market, and secondary equity markets, which consist primarily of public and OTC markets.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(610, 'Equity Co-Investment', 'Equity coinvestments are investments made in a company through a private equity LP.  ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(611, 'Equity Fund', ' An equity fund is a mutual fund that invests principally in stocks. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(612, 'Equity Market', ' Equity markets are meeting points for issuers and buyers of stocks in a market economy. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(613, 'Equity Premium Puzzle (EPP)', ' The equity premium puzzle (EPP) is a phenomenon that describes the anomalously higher historical real returns of stocks over government bonds. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(614, 'Equity Risk Premium', ' Equity risk premium refers to the excess return that investing in the stock market provides over a riskfree rate. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(615, 'Escrow Agreement', 'An escrow agreement is a legal document outlining terms and conditions between parties as well as the responsibility of each.  ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(616, 'Escrowed Shares', ' Scrowed shares are shares held in an escrow account, secured by a third party, pending the completion of a corporate action or an elapse of time leading up to an event.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(617, 'Ethical Investing', 'Ethical investing is the practice of selecting investments based on ethical or moral principles.  ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(618, 'Euroclear', ' Euroclear is one of two principal securities clearing houses in the Eurozone. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(619, 'Euromarket', ' In finance, it is the market for eurocurrencies these are all currencies that are held outside their country of issue.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(620, 'Europe, Middle East, and Africa (EMEA)', ' Europe, Middle East, and Africa (EMEA) countries are a geographical division used by many multinational corporations. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(621, 'European Union (EU)', ' The European Union (EU) consists of a group of countries that acts as one economic unit in the world economy. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(622, 'Excess Cash Flow', ' Excess cash flow is typically cash received or generated by a company that triggers a payment to the lender as stipulated in the credit agreement.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(623, 'Exchange', ' An exchange is a marketplace where securities, commodities, derivatives and other financial instruments are traded.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(624, 'Exchange of Futures for Physical (EFP)', ' An exchange of futures for physical (EFP) is a private agreement between two parties to trade a futures position for the basket of underlying actuals. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(625, 'Exchange Traded Fund (ETF)', ' An exchangetraded fund (ETF) is a type of security that involves a collection of securitiessuch as stocksthat often tracks an underlying index, although they can invest in any number of industry sectors or use various strategies.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(626, 'Ex-Dividend', ' Exdividend stocks are those which are trading without the value of the next dividend.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(627, 'Ex-Dividend Date', ' The exdividend date, or exdate for short, is one of four stages that companies go through when they pay dividends to their shareholders.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(628, 'Exempt-Interest Dividend', ' An exemptinterest dividend is a distribution from a mutual fund that is not subject to federal income tax. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(629, 'Exit Load', ' Exit load is charged at the time an investor redeems the units of a mutual fund.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(630, 'Exit Strategy', ' An exit strategy is a contingency plan that is executed by an investor, trader, venture capitalist, or business owner to liquidate a position in a financial asset or dispose of tangible business assets once predetermined criteria for either has been met or exceeded.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(631, 'Expected Return', ' The expected return is the amount of profit or loss an investor can anticipate receiving on an investment.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(632, 'Expected Value (EV)', ' The expected value (EV) is an anticipated value for an investment at some point in the future.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(633, 'Expense Ratio', ' The expense ratio (ER) is a measure of mutual fund operating cost relative to assets.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(634, 'Export Trading Company (ETC)', ' An export trading company (ETC) handles the exportation process for clients, navigating all legal requirements and regulations that a company must follow before a country will allow its goods to be exported.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(635, 'External Debt', ' External debt is the portion of a countrys debt that was borrowed from foreign lenders, including commercial banks, governments, or international financial institutions.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(636, 'Face Value', 'Face value describes the nominal value or dollar value of a security the face value is stated by the issuing party. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(637, 'Fair Labor Standards Act', ' The Fair Labor Standards Act (FLSA) is a U.S. law that is intended to protect workers against certain unfair pay practices or work regulations.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(638, 'Fallen Angel', 'A fallen angel is a bond that has been reduced to junk status because its issuer has fallen into financial trouble. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(639, 'Fama and French Three Factor Model', ' The Fama French 3factor model is an asset pricing model that expands on the capital asset pricing model by adding size risk and value risk factors to the market risk factors.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(640, 'Federal Discount Rate', ' The Federal discount rate is the interest rate the Federal Reserve charges banks to borrow funds, while the federal funds rate is the rate banks charge each other. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(641, 'Federal Funds', ' Federal funds refer to excess reserves held by financial institutions, over and above the mandated reserve requirements of the central bank.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(642, 'Federal Reserve Board (FRB)', ' The Board of Governors of the Federal Reserve System, also known as the Federal Reserve Board (FRB), is the governing body of the Federal Reserve System.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(643, 'Federal Reserve System (FRS)', ' The Federal Reserve System (FRS) is the central bank of the United States and arguably the most powerful financial institution in the world.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(644, 'Feeder Fund', ' A feeder fund is one of many smaller investment funds that pool investor money, which is then aggregated under a single centralized master fund.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(645, 'Fiat Money', ' Fiat money is governmentissued currency that isnt backed by a commodity such as gold.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(646, 'Financial Crisis', ' In a financial crisis, asset prices see a steep decline in value, businesses and consumers are unable to pay their debts, and financial institutions experience liquidity shortages. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(647, 'Financial Guarantee', ' Financial guarantees are essentially insurance policies that guarantee that a particular debt issue will be paid if the debt issuer experiences financial difficulties.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(648, 'Financial Markets', ' Financial markets refer broadly to any marketplace where the trading of securities occurs, including the stock market, bond market, forex market, and derivatives market, among others. Financial markets are vital to the smooth operation of capitalist economies.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(649, 'Financial Plan', ' A financial plan is a comprehensive statement of an individuals longterm objectives for security and wellbeing and a detailed savings and investing strategy for achieving those objectives.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(650, 'Fisher Effect', ' The Fisher Effect is an economic theory created by economist Irving Fisher that describes the relationship between inflation and both real and nominal interest rates.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(651, 'Fixed Exchange Rate', ' A floating rate fund is a fund that invests in financial instruments paying a variable or floating interest rate.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(652, 'Floating Stock', ' Floating stock is the outstanding shares minus those that are restricted, or held by insiders or major shareholders.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(653, 'Flow Of Funds (FOF)', ' Flow of funds accounts are used to track the flow of money to and from various sectors of a national economy. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(654, 'FMP (Fixed Maturity Plans)', ' Fixed maturity plans (FMPs) are a special class ofcloseended debt mutual fundsthat mature after completion of a predetermined time period.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(655, 'Folio Number', ' In mutual funds, a folio number is a unique number identifying your account with the fund.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(656, 'Follow On Public Offer (FPO)', ' A followon public offer (FPO) is another issuance of shares after the initial public offering (IPO). ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(657, 'Follow-On Offering', ' A followon offering (FPO) is an issuance of stock shares following a companys initial public offering (IPO).', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(658, 'Foreign Currency Convertible Bond (FCCB)', ' A foreign currency convertible bond (FCCB) is a type of convertible bond issued in a currency different than the issuers domestic currency. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(659, 'Foreign Direct Investment (FDI)', ' Foreign direct investments (FDI) are investments made by one company into another located in another country.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(660, 'Foreign Investment', '  Foreign investment involves capital flows from one country to another, granting extensive ownership stakes in domestic companies and assets.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(661, 'Foreign Portfolio Investment (FPI)', ' Foreign portfolio investment (FPI) involves holding financial assets from a country outside of the investors own.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(662, 'Forfeited Share', 'A forfeited share is a share in a publiclytraded company that the owner loses (or forfeits) by neglecting to live up to any number of purchase requirements. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(663, 'Form 1099-DIV: Dividends and Distributions', ' Form 1099DIV is sent to investors who receive distributions from any type of investment during a calendar year.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(664, 'Forward Dividend Yield', ' A forward dividend yield is the percentage of a companys current stock price that it expects to pay out as dividends over a certain time period, generally 12 months.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(665, 'Fractional Share', ' A fractional share is a portion of an equity stock that is less than one full share.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(666, 'Franked Dividend', ' A franked dividend is paid with a tax credit attached and is designed to eliminate the issue of double taxation of dividends for investors.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(667, 'Free Cash Flow to Equity ГўвӮ¬вҖң FCFE', ' Free cash flow to equity is a measure of how much cash is available to the equity shareholders of a company after all expenses, reinvestment, and debt are paid. FCFE is a measure of equity capital usage.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(668, 'Free On Board (FOB)', ' Free On Board is a term used to indicate who is liable for goods damaged or destroyed during shipping.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(669, 'Fund', ' A fund is a pool of money set aside for a specific purpose.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(670, 'Fund Flow', ' Fund flow is the net of all cash inflows and outflows in and out of various financial assets. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(671, 'Fund Manager', ' A fund manager is responsible for implementing a funds investment strategy and managing its trading activities.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(672, 'Fund Of Funds (FOF)', ' A fund of funds (FOF)also known as a multimanager investmentis a pooled investment fund that invests in other types of funds.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(673, 'Future Value (FV)', '  Future value (FV) is the value of a current asset at some point in the future based on an assumed growth rate.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(674, 'GAFAM Stocks', ' GAFAM is an acronym for the five most popular U.S. tech stocks Google, Apple, Facebook, Amazon and Microsoft.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(675, 'Gain', ' A gain is the positive difference between what you pay for an asset and what you sell it for. If the difference is negative, it is a loss.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(676, 'General Obligation Bond (GO)', ' A general obligation bond (GO) is a municipal bond backed by the credit and taxing power of the issuing jurisdiction rather than the revenue from a given project. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(677, 'General Public Distribution', ' A general public distribution is a type of primary market offering in which the securities being issued are available to anyone who has the ability to purchase them.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(678, 'Gift of Equity', ' A gift of equity involves the sale of a residence at a price below its current market value.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(679, 'Gilt Funds', ' Fund that invests exclusively in government securities.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(680, 'Gilt-Edged Securities', ' Giltedged securities refer to highgrade bonds that some national governments and private organizations issue in an effort to generate revenue.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(681, 'Gilts', ' Government bonds in the U.K., India, and several other commonwealth countries are known as gilts.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(682, 'Give Up', ' In a giveup agreement, an executing broker places a commodity or security trade on behalf of another broker.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(683, 'Glide Path', ' Glide path refers to a formula that defines the asset allocation mix of a targetdate fund, based on the number of years to the target date.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(684, 'Global Depositary Receipt (GDR)', ' A global depositary receipt (GDR) is a bank certificate issued in more than one country for shares in a foreign company.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(685, 'Global Fund', ' A global fund is a fund that invests in companies located anywhere in the world including the investors own country.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(686, 'Global Industry Classification Standard (GICS)', ' The Global Industry Classification Standard (GICS) is a standardized classification system for equities, developed jointly by Morgan Stanley Capital International (MSCI) and Standard  Poors.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(687, 'Global Macro Hedge Fund', ' Global macro hedge funds are actively managed funds that attempt to profit from broad market swings caused by political or economic events.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(688, 'Global Macro Strategy', ' A global macro strategy bases its holdings on the economics and politics of various countries or their macroeconomic principles.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(689, 'Global Registered Share (GRS)', ' A global registered share (GRS, or Global Share) is a security that is issued in the United States but is registered in multiple markets around the world and trades in multiple currencies.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(690, 'Go-Go Fund', ' Gogo fund is a slang name for a mutual fund that has an investment strategy focused on highrisk securities in an attempt to capture aboveaverage returns.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(691, 'Golden Share', ' A golden share is a type of share that gives its shareholder veto power over changes to the companys charter.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(692, 'Government Bond', ' A government bond is a form of debt security issued by a government and sold to investors to support government spending.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(693, 'Government Of Singapore Investment Corporation (GIC)', ' The Government of Singapore Investment Corporation (GIC) is a governmentowned company assigned to manage Singapores sovereign wealth fund.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(694, 'Government Security', ' Government securities come with a promise of the full repayment of invested principal at maturity of the security.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(695, 'Grant Deed', ' A grant deed is a legal document used to transfer ownership of real property and proving that the title has not already been granted to another person.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(696, 'Gray Market', ' The gray market for financial securities refers to unofficial, overthecounter (OTC) transactions in a security.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(697, 'Great Depression', ' The Great Depression was the greatest and longest economic recession in modern world history. It began with the U.S. stock market crash of 1929 and did not end until 1946 after World War II.24.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(698, 'Green Fund', ' A green fund is a mutual fund or another investment vehicle that will only invest in companies that are deemed socially conscious in their business dealings or directly promote environmental responsibility.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(699, 'Green Investing', ' Green investing refers to investing activities aligned with a commitment to the promotion of environmentally friendly business practices and the conservation of natural resources.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(700, 'Gross Dividends', ' Gross dividends, for tax purposes, include all ordinary dividends plus capital gains distributions and nontaxable distributions.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(701, 'Gross Processing Margin (GPM)', ' The gross processing margin (GPM) is the difference between the cost of a raw commodity and the income generated once the commodity has been sold as a finished product.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(702, 'Gross Rate of Return', ' A gross rate of return is reflective of an investments return before expenses or any deductions.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(703, 'Gross Yield', ' The gross yield of an investment is its profit before taxes and expenses are deducted. Gross yield is expressed in percentage terms. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(704, 'Growth And Income Fund', ' A growth and income fund is a mutual fund or ETF strategy that seeks a total return for investors including capital gains and current income.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(705, 'Growth Fund', ' A growth fund is a diversified portfolio of stocks that has capital appreciation as its primary goal, with little or no dividend payouts.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(706, 'Growth Funds', ' Unit trusts or Mutual Funds which invest with the objective of achieving mostly capital growth rather than income.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(707, 'Growth Investing', ' Growth investing is a stockbuying strategy that focuses on companies expected to grow at an aboveaverage rate compared to their industry or the market.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(708, 'Growth Option', ' Whatever interests, bonus, gains and dividends the fund earns is not paid out or distributed amongst the investors. It is ploughed back and reinvested in the scheme itself. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(709, 'Growth Stock', ' A growth stock is a share in a company that is anticipated to grow at a rate significantly above the average for the market.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(710, 'GSCI S&P', ' The SP GSCI is a composite index of commodities that measures the performance of the commodity market.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(711, 'Guaranteed Stock', ' Guaranteed stock is a rarely used form of preferred stock, where a party other than the original company guarantees dividends will be paid.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(712, 'Guilder Share (New York Share)', ' An ownership stake in a Dutch company that can be traded in the United States because it represents shares that have been canceled in Dutch markets.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(713, 'Half Stock', ' A half stock is a type of security sold with a face value that is roughly half of what is considered to be the standard price.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(714, 'Hands-Off Investor', ' A handsoff investor prefers to set an investment portfolio and make only minor changes for a long period of time. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(715, 'Hang Seng Index (HSI)', ' The Hang Seng Index (HSI) is a benchmark for bluechip stocks traded on the Hong Kong stock exchange.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(716, 'Hedge Clause', ' A hedge clause is a clause in a research report that attempts to absolve the writer of any responsibility for the accuracy of information included in the report or publication. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(717, 'Hedge Fund Manager', ' A hedge fund manager is a financial company or individual that employs professional portfolio managers and analysts in order to establish hedge funds.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(718, 'Hedging Transaction', ' Hedging transactions are usually derivative purchases to reduce the risk of investments.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(719, 'Heritage and Stabilization Fund (HSF)', ' The Heritage and Stabilization Fund is a sovereign wealth fund that was established in March 2007 by the government of the Republic of Trinidad and Tobago. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(720, 'Hiccup', ' Hiccup is a slang term for a shortterm disruption within a longerterm plan, goal, or trend.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(721, 'High Beta Index', ' A high beta index is a basket of stocks that exhibit greater volatility than a broad market index like the SP 500.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(722, 'Historic Pricing', ' Historic pricing is a unit pricing method used to calculate the value of an asset using the last valuation point calculated.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(723, 'Historical Volatility (HV)', ' Historical volatility (HV) is a statistical measure of the dispersion of returns for a given security or market index over a given period of time.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(724, 'Hold', ' A hold recommendation means that the analyst making it doesnt see the stock in question outperforming or underperforming comparable stocks in the near term.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(725, 'Holder Of Record', ' A holder of record is the name of the person who is the registered owner of a security and who has the rights, benefits and responsibilities of ownership.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(726, 'Holding Period Return/Yield', ' Holding period return (or yield) is the total return earned on an investment during the time that it has been held.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(727, 'Holdings', ' The holdings or the portfolio is a mutual funds latest or updated reported statement of investmentssecurities.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(728, 'Home Bias', ' Home bias is the tendency for investors to invest the majority of their portfolio in domestic equities, ignoring the benefits of diversifying into foreign equities.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(729, 'Homemade Dividends', ' Homemade dividends signify a category of investment income that results from the partial sale of an investors portfolio. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(730, 'Homemade Leverage', ' Homemade leverage is used by an individual investor to artificially adjust the leverage of a company.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(731, 'Hong Kong Exchanges and Clearing Limited (hkex)', ' Hong Kong Exchanges and Clearing Limited (hkex) is a publiclytraded holding company that promotes itself as one of the biggest market operations in the world.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(732, 'Horizontal Market', ' A horizontal market is diversified so that the products created are able to meet the needs of more than one industry. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(733, 'H-Shares', ' Hshares are shares of Chinese mainland companies that are listed on the Hong Kong Stock Exchange or other foreign exchange.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(734, 'Hurdle Rate', ' A hurdle rate is the minimum rate of return required on a project or investment.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(735, 'Import', ' An import refers to a product or service produced in abroad that is purchased in your home country.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(736, 'Imputed Interest', ' Imputed interest is used for tax revenue on loans that pay little interest.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(737, 'In Specie', ' In specie is the delivery of a financial asset in its current form rather than in an equivalent amount of cash.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(738, 'Income Stock', ' Income stocks are stocks that offer regular and steady income, usually in the form of dividends, over a period of time with low exposure to risk.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(739, 'Index', ' An index measures the performance of a basket of securities intended to replicate a certain area of the market, such as the Standard  Poors 500.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(740, 'Index Fund', ' An index fund is a portfolio of stocks or bonds designed to mimic the composition and performance of a financial market index.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(741, 'Indexation Benefit', ' Indexation is an option available for investors to manage their inflationadjusted returns.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(742, 'Indexing', ' Indexing is the practice of compiling economic data into a single metric.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(743, 'Indication of Interest (IOI)', ' Indications of interest (iois) are nonbinding agreements to buy a security once available.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(744, 'Indicative Net Asset Value (inav)', ' Indicative net asset value (inav) is a measure of the intraday net asset value (NAV) of an investment. It is reported approximately every 15 seconds.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(745, 'Inefficient Market', ' An inefficient market is one that does not succeed in incorporating all available information into a true reflection of an assets fair price.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(746, 'Inflation', ' Inflation is the rate at which the general level of prices for goods and services is rising and, consequently, the purchasing power of currency is falling.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(747, 'Inflection Point', ' An inflection point is an event that results in a significant change in the progress of a company, industry, sector, economy, or geopolitical situation.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(748, 'Information Coefficient (IC)', ' The information coefficient (IC) is a measure used to evaluate the skill an investment analyst or active portfolio manager. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(749, 'Institution Investors', ' Organizations those invest, including insurance companies, depository institutions, pension funds, investment companies, and endowment funds.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(750, 'Interest', ' Interest is the charge for the privilege of borrowing money, typically expressed as annual percentage rate (APR).', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(751, 'Interest Rate', 'The interest rate is the amount charged on top of the principal by a lender to a borrower for the use of assets. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(752, 'Interest Rate Risk', ' Interest rate risk is the potential that a change in overall interest rates will reduce the value of a bond or other fixedrate investment.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(753, 'Interim Dividend', ' An interim dividend is typically one of two dividends given out by a company that is providing shareholders with income on a semiannual basis', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(754, 'Investing', ' Investing is the act of allocating funds to an asset or committing capital to an endeavor (a business, project, real estate, etc.), with the expectation of generating an income or profit.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(755, 'Investment', ' Investment is the act of putting money to work to start or expand a business or project or the purchase of an asset, with the goal of earning income or capital appreciation.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(756, 'Investment Advisor', ' Investment advisors are financial professionals that make investment recommendations or conduct security analysis in exchange for a fee.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(757, 'Investment Analysis', ' Investment analysis involves researching and evaluating a security or an industry to predict its future performance and determine its suitability to a specific investor.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(758, 'Investment Bank (IB)', ' Investment banks specialize in complex financial transactions, such as underwriting, ipos, facilitating mergers and other corporate reorganizations and acting as a broker or financial advisor.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(759, 'Investment Banker', ' An investment banker is an individual who often works as part of a financial institution and is primarily concerned with raising capital for corporations, governments or other entities.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(760, 'Investment Company', ' An investment company is a corporation or trust engaged in the business of investing pooled capital into financial securities.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(761, 'Investment Fund', ' An investment fund is a supply of capital belonging to numerous investors used to collectively purchase securities while each investor retains ownership and control of his own shares.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(762, 'Investment Horizon', ' An investment horizon refers to the length of time that an investor is willing to hold the portfolio for.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(763, 'Investment Policy Statement (IPS)', ' An investment policy statement (IPS) is a document drafted between a portfolio manager and a client that outlines general rules for the manager.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(764, 'Investment Strategy', 'An investment strategy is what guides an investors decisions based on goals, risk tolerance, and future needs for capital ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(765, 'Investment Thesis', ' An investment thesis is a written document that recommends a new investment, based on research and analysis of its potential for profit.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(766, 'Investor Relations (IR)', ' The investor relations department (IR) is present in most mediumtolarge public companies that provides investors with an accurate account of company affairs', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(767, 'Ishares', ' Ishares is one of the worlds largest and wellknown ETF providers, offering more than 800 products worldwide.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(768, 'Issuer', ' An issuer is a legal entity that develops, registers and sells securities to finance its operations.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(769, 'Jackpot', ' A jackpot is a large windfall derived from an act of gambling. In finance, jackpots refer to large investment returns reaped over a short period of time.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(770, 'Jakarta Stock Exchange (JSX)', ' The Indonesia Stock Exchange (IDX), created by the merger of Jakarta Stock Exchange (JSX) and the Surabaya Stock Exchange (SSX), handles securities transactions in the country.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(771, 'Japan ETF', ' A Japan ETF is a type of exchangetraded fund that invests the majority of its assets in Japanese equities that trade on local stock exchanges.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(772, 'Jarrow Turnbull Model', ' The Jarrow Turnbull model is one of the first reducedform models for pricing credit risk.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(773, 'Jitney', ' N finance, the term jitney refers to a broker that does not have direct access to an exchange and therefore relies on another broker with exchange access in order to execute their trades.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(774, 'Job Market', ' Employers search for employees and employees search for jobs in the job market.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(775, 'Jobber', ' A jobber is a slang term for a market maker on the London Stock Exchange prior to October 1986. Jobbers, also called stockjobbers, acted as market makers. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(776, 'John Bogle', ' John Bogle was the founder of the Vanguard Group and a major proponent of index investing. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(777, 'Joint Tenants With Right of Survivorship (JTWROS)', ' Joint tenants with right of survivorship (JTWROS) is a type of brokerage account owned by at least two people, where all tenants have an equal right to the accounts assets and are afforded survivorship rights in the event of the death of another account holder. The concept also applies to real estate property.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(778, 'Joint-Stock Company', ' A jointstock company is a business owned collectively by its shareholders.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(779, 'Junior Debt', ' Junior debt is debt that has a lower priority for repayment than other debt claims in the case of default. ', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(780, 'Junior Equity', ' Junior equity is stock issued by a company that ranks at the bottom of the priority ladder in terms of ownership structure.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(781, 'Junior Security', ' Junior securities have a lower priority of claim on assets or income compared to senior securities.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(782, 'Junk bond', ' A lowerrated, usually higheryielding bond, with a credit rating of BB or lower.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(783, 'Contra Fund', 'It follows a contrarian investment strategy. The strategy involves buying  selling in opposite to the present market sentiments.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(784, 'Equity linked saving scheme (ELSS)', 'ELSS is the only tax saving scheme under section 80(c) of the IT Act. Investment upto  1.5 lakh in ELSS is eligible for deduction from taxable income. The scheme comes with a strategy lock in period of 3 years for each SIP.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:34:38', '2022-02-08 10:34:38'),
(785, 'Tax saving Scheme', 'It offers tax rebates to the investors under the provision of Income Tax Act, 1961.', 1, 1, 1, '2022-02-08 10:34:38', '2022-02-08 10:36:13', '2022-02-08 10:34:38');
INSERT INTO `mpx_fund_man` (`fm_id`, `name`, `slug`, `media_id`, `designation`, `company_name`, `synopsis`, `description`, `status`, `created_id`, `updated_id`, `created_at`, `updated_at`, `migration_at`) VALUES
(1, 'Shreyas Devalkar', 'shreyas-devalkar', 4, 'Fund Manager', 'Axis Mutual Fund', 'Shreyas is a Mumbai person through and through with his education and sensibilities totally forged in the Mumbai milieu except one major aspect he is an average cricket follower but more of a squash,tennis fan and plays both these when possible', '<p>Shreyas is a Mumbai person through and through with his education and sensibilities totally forged inthe Mumbai milieu.except one major aspect he is an average cricket follower but more of a squash,tennis fan and plays both these when possible.</p><p>A Graduate degree in Chemical Engineering from UDCT (University of Bombay) and a post graduate in business studies from Jamnalal Bajaj Institute of Management Studies (University of Mumbai), he is a person who knows the train stations very well.</p><p>A family man he would like to take a vacation more often than he has so far but a vacation that offersopportunities to chill and do nothing and maybe a little bit of adventure. But so far his holidays have been meshed with the days when the markets are closed for a longer span. And on his holiday, he would much rather read a book than watch a movie. And munching on some of his favourite guilty pleasures like chocolates and mithais.</p><p><b>Some feedback on the current situation from the Man:</b></p><p><b>Your evaluation of the economic consequences of the COVID 19 pandemic and how long do you think we would need to get back to normal?</b></p><p>The crux of the current issue is Social Distancing. Both in terms of the problem as well as the solution.The problem persists because of a disregard for SOCIAL DISTANCING and it will mitigate with more awareness and with SOCIAL DISTANCING. As of now it is a bigger health crisis than an economic crisis but there is every chance, if this persists and takes the upper hand, there will be an economic crisis.The pandemic has remained manageable because of social distancing but the caution made so far should not be thrown away. As the country opens up gradually, we should maintain social distancing asour first and foremost defence.</p><p><b>How and where all do you see the effect of COVID 19 panning out?</b></p><p>The effects of the pandemic will be in capacity utilization, and I am speaking as an observer and not an expert. Capacity utilization will not only be there in factories and offices but also in many other different places. Primarily, capacity utilization in public places will be constrained. Parks, markets, public amenities  all these will have limited usage. Added of course are the other obvious ones like malls,restaurants, movie halls, offices and so on. Commercial real estate would be hit and so also would the individual real estate.</p><p>There will be a significant impact on consumption. Not only would absolute consumption get affected,but also would the pattern of consumption. The content of consumption would see a high change. And what many people dont talk about  the frequency of consumption would be seeing a substantial change.</p><p>An obvious first casualty is the leisure sector, consisting of hotels, resorts, airlines and other travel options and all entertainment options.As far as the markets are concerned, there would be some sectors taking a big hit while some others will be doing much better. Telecom is the biggest beneficiary and will show improved results. Some others like OTT platforms are also big beneficiaries but there are not many listed entities in the space.</p><p><b>What is the road to normalcy?</b></p><p>Nobody can predict the time or the route to normalcy and there are experts looking into it and analyzing trends regularly. There has been and will be disruptions to our lives. Job losses, salary cuts for people and earnings losses for companies. The problem will not go away till a vaccine is made available. The longer the duration the more lasting the consequences there will be.</p>', 1, 1, 1, '2020-05-24 05:30:00', '2022-02-17 13:00:13', '2022-02-17 12:34:32'),
(2, 'Aniruddha Naha', 'aniruddha-naha', 2, 'Director & Senior Fund Manager', 'PGIM Investments', 'Aniruddha Naha is a Kolkata boy dealing in big money today with the hallowed PGIM India outfit. Living with his wife and two children and mother, his is a story of ticking all the right boxes at the right time. Coming across as a serious person, as most fund managers do, it is only when you start talking out of the books, pun fully intended, that the twinkle in his eyes get you and the little naughty boy growing up emerges.', '<p>Aniruddha Naha is a Kolkata boy dealing in big money today with the hallowed PGIM India outfit. Living with his wife and two children and mother, his is a story of ticking all the right boxes at the right time. Coming across as a serious person, as most fund managers do, it is only when you start talking out of the books, pun fully intended, that the twinkle in his eyes get you and the little naughty boy growing up emerges. With his student days spent in St. Xaviers Kolkata and followed up with the Delhi University stint, pursuing a Masters in Finance, could it be any different!!</p>\r\n\r\n<p>I loved the way and I am sure you will too, with the way he answers the candid questions and realize he could be a fun person around when he is not buying/selling his way around.</p>\r\n\r\n<p>For example:<br>\r\n<strong>Can you tell us something crazy stupid you did growing up but that brings a smile many years hence</strong></p>\r\n\r\n<p>Quite a few but worth sharing only in person.</p>\r\n\r\n<p>He loves to spend a Sunday maybe going out for a long drive or maybe cooking up some magic in the kitchen.and why am I not surprised.As for the rest, I am sure you will have a better insight into the man apart from the fund manager person.</p>\r\n\r\n<p>Are you a micro manager outside of work? Or you let issues reach you before you act on them?</p>\r\n\r\n<p>I am pretty laid back. Incase I dont need to interfere, very happy to lay back and see things moving on without any interventions.</p>\r\n\r\n<p><strong>What is your best holiday so far? And why?</strong></p>\r\n\r\n<p>Kenya and Tanzania. It gave me an opportunity to feel mother Earth in its most primate form. Roam through the safaris in a vehicle with absolutely no connection with modern world, zero Wi-Fi signals over a fortnight is an experience to cherish.</p>\r\n\r\n<p><strong>Do you take frequent holidays or do you wait for taking a long one (both job permitting of course). are they planned or on the spur of the moment?</strong></p>\r\n\r\n<p>We love to travel, so its usually one long holiday and I plan holidays over the weekend, whenever possible</p>\r\n\r\n<p><strong>Between books-movies.what would you choose? Which hero did or do you worship?</strong></p>\r\n\r\n<p>Movies. More than an actor, I look forward to any new film by Quentin Tarantino, which unfortunately are far and few.</p>\r\n\r\n<p><strong>What genre of books do you like and who is your fave author?</strong></p>\r\n\r\n<p>Thrillers.John Grisham</p>\r\n\r\n<p><strong>Top cuisines you prefer and how familiar are you with the kitchen?</strong></p>\r\n\r\n<p>Middle Eastern and Continental. You will find me often in the kitchen in my free time</p>\r\n\r\n<p><strong>Are you a sports buff? What is your favourite sport? Sportsperson?</strong></p>\r\n\r\n<p>Like watching Cricket, football and UFC (my response seriously?? UFC And football..wow)</p>\r\n\r\n<p><strong>What are your other interests and hobbies?</strong></p>\r\n\r\n<p>Travelling, films, cooking</p>\r\n\r\n<p>Dispensing off with the personal, delving into his investment worldview:</p>\r\n\r\n<p><strong>As the world (apart from the US) SLOWLY SETTLES DOWN INTO A POST Covid Era where do you think the world has changed from then and now and going forward how do you think the old normal will return?</strong></p>\r\n\r\n<p>The Post Covid scenario is still evolving. The hope of a vaccine in the next 6-18 months will determine the final outcome of the post Covid scenario. It will be fair to assume that, some businesses will take far longer to return back to normal like businesses related to travel, tourism and hospitality.</p>\r\n\r\n<p>The longer the world works from home, the more comfortable the new normal becomes. This will have an impact on real estate and the office rental space. This space, due to the higher ticket size, will most likely face a lot of disruptions and will lead to a pressure on pricing. The slowdown in the economy creates uncertainty in the job market and will impact the wallets of consumers. In the near future, we foresee an impact on discretionary consumption and the impact will be higher on larger ticket items. Hence, people may continue to buy a TV or AC but the there would be impact on holiday budgets, purchase of personal mobility items.</p>\r\n\r\n<p>A large part of normalcy will start happening, once a reasonably priced vaccine is discovered, which could be 12-24 months.</p>\r\n\r\n<p><strong>What are the biggest learnings in the last 4 months for you?</strong></p>\r\n\r\n<p>As a philosophy, we have always tried to protect the downside by focusing on good businesses with strong operating cashflows (OCF) and strong balance sheets. The last few months in the extreme volatility, we have seen the strength of strong cashflows and balance sheets playing out, where such good businesses continue to outperform. There is no substitute to buying good businesses at reasonable valuations.</p>\r\n\r\n<p><strong>What are the significant pluses and minuses of the India economy? And what do you think needs immediate intervention and improvement?</strong></p>\r\n\r\n<p>The Indian economy has the demographic dividend curve on its side along with the fact that it is young population which speaks English. Growing incomes can fuel a strong consumption cycle over the next decade. The economy has a strong captive customer base within the country, which would take of the demand side for any business. Whether it is the consumption side or the investment side, there is a large under penetration and lot needs to be done, which itself could drive both the investment cycle and the consumption cycle. The biggest shortfall for the Indian economy happens to be the lack of adequate capital to grow. The financial system is going through a consolidation phase and funding is reaching the overall businesses, which is aggravating the pain in the balance sheets of the SME businesses.</p>\r\n\r\n<p>India has also lacked investments on the technology front and this is a space where corporates and the government need to focus on, in terms of building self-reliance on indigenous technology.</p>\r\n\r\n<p><strong>If you were to make one suggestion for the Indian economy, what would it be?</strong></p>\r\n\r\n<p>The government has incentivized setting up new businesses by bringing down the tax rate for new manufacturing units. Easing of the processes of approvals for setting up of new businesses both at a state and central level with regards to approvals can go a long way in converting business plans from the drawing boards to reality.</p>\r\n\r\n<p>And I ask this question of everyone I meet/talk to for an interview</p>\r\n\r\n<p><strong>You have spent close to two decades in the fund management space. What will you advice aspiring fund managers (college kids)?</strong></p>\r\n\r\n<p>There is clearly no set formula for become an aspiring fund manager. The interest must be in studying macro trends, understanding businesses, and looking at their financials. Other than the academics, which is of utmost importance, with a proficiency of reading annual reports and deciphering numbers, students need to build a knack of understanding businesses.</p>', 1, 1, 1, '2020-08-21 05:30:00', '2022-02-17 12:59:30', '2022-02-17 12:34:32'),
(3, 'Shridatta Bhandwaldar', 'shridatta-bhandwaldar', 6, 'Head Equities', 'Canara Robeco Mutual Fund', 'Shridatta Bhandwaldar, popularly called Shri, though not a dyed in the wool Aamchi Mubaikar, has struck deep roots in the city of his choice. But like all, not from the city, he looks for every opportunity to get back to his hometown Aurangabad.', '<p><strong>Shridatta Bhandwaldar,</strong> popularly called Shri, though not a dyed in the wool Aamchi Mubaikar, has struck deep roots in the city of his choice. But like all, not from the city, he looks for every opportunity to get back to his hometown Aurangabad. A qualified Engineer and a finance professional, he has the company of the charming Suhasini and the lovable kids Ananya and Manas to keep him grounded. The kids share a sporty bond with the money manager dad, who, when he gets the time delves into reading and music.</p>\r\n\r\n<p>Reading takes precedence (but not the thrillers) but largely books that talk about money management and investment ideas<em> <strong>(Why am I not surprised??)</strong></em> and the obvious preference for authors remains the Warren Buffets and Nassim Talebs <em><strong>(why am I not surprised?)</strong></em>. ShridattaвҖҷs curiosity in human psychology and behavioral dynamics is met by Daniel Kahnemann and options for sharing wealth and charity also line his bookshelf in large numbers. Our man knows his way around the kitchen too and if you drop by, he might rustle you a mean Alu sabji, Aurangabad style. Be nice and he might give you some roti too!!! Cricket was a passion growing up but now itвҖҷs Tennis and Roger Federer that he watches and idolizes.</p>\r\n\r\n<p>A person not in the habit of micro managing or going looking for issues, he is a person who thinks about crossing a bridge once he reaches it and doing so, he has taken some holiday destinations off the usual track. But the one quality that draws him to Shillong, his fave holiday destination, is the serenity and the sublime beauty of the place. Although taking holidays are important, they donвҖҷt happen as much as he would wish them.</p>\r\n\r\n<p><strong>Some direct questions and answers from Shridatta.</strong></p>\r\n\r\n<p><strong>Were you always interested in fund management or did you have any other aspiration?</strong></p>\r\n\r\n<p>Yes. Started with Equity Research and so it was natural progression in career.</p>\r\n\r\n<p><strong>Can you please tell us a bit about your journey to your current position in Canara Robeco?</strong></p>\r\n\r\n<p>I started as a FM in JulyвҖҷ2016, managing three key funds for the organization Viz. Canara Robeco Bluechip, Diversified and Balance Fund. These three funds have done well over last 3-4 years. When there was a possibility, the organization decided to give me this opportunity as a Head of Equity.</p>\r\n\r\n<p><strong>The Canara Robeco Equity schemes overall have shown marked improvement over the last few years. What are you doing differently that has made the improvements?</strong></p>\r\n\r\n<p>The key thing at Canara Robeco has been focus on underlying businesses. Our consistent focus on Business, Management and Valuation (BMV) has helped us to be in relatively good position over period.</p>\r\n\r\n<p><strong>What is your outlook on gold as an investment?</strong></p>\r\n\r\n<p>Gold still has some steam left and the growth in prices is likely to continue for the next two years, till economic activity picks up steam.</p>\r\n\r\n<p><strong>What is your opinion of Index funds? How are they likely to impact the index components in case of sudden surge of money into them or redemptions out of them?</strong></p>\r\n\r\n<p>I think from Indian perspective there is still long way for Index funds to become meaningful. The core reason why active fund managers have lot of scope to generate alpha in India is, the continuous changes that are happening in the index itself. I think until we reach ~5000 dollar per capita country, this economy, sectors and thus indices will keep evolving and this churn is good for ability to generate active returns against index. Flows will clearly create sudden dislocations in index weights for individual securities.</p>', 1, 1, 1, '2020-08-21 05:30:00', '2022-02-17 12:58:28', '2022-02-17 12:34:32'),
(4, 'Sanjay Chawla', 'sanjay-chawla', 5, 'Chief Investment Officer', 'Baroda Asset Management India Limited', 'Sanjay is an out and out Mumbai born and raised person and had his school and college days merrily spent in the city of his birth. Initial school days were full of sports and outdoorsy activities, of which, all I am told, should not be shared here. Suffice to say that if and when his children play hooky and attempt to pull a fast one over the dad, Sanjay would probably first smile to himself before reacting.', '<p>Sanjay is an out and out Mumbai born and raised person and had his school and college days merrily spent in the city of his birth. Initial school days were full of sports and outdoorsy activities, of which, all I am told, should not be shared here. Suffice to say that if and when his children play hooky and attempt to pull a fast one over the dad, Sanjay would probably first smile to himself before reacting. Having put himself through the rigours of studies growing up with hostel life at BITS Pilani and then again with serious academics while completing his MMS from the University of Bombay, surely he must have gone through it all. A workaholic and in his own words, disturbingly so, he is obsessed with the investments thoughts and ideas even out of the working hours.</p>\r\n\r\n<p>An ideal Sunday is spent rustling up some goodies in the kitchen and perhaps follow up with a fun outing or a movie. Understandably the rigours of the job does not allow the luxury of quick getaways, which is compounded by the childrenвҖҷs study schedules and co-curricular commitments. However the vacation spent in New Zealand has left a deep impression. Obviously, the pristine landscape and breathtaking beauty of the place ticked all the right boxes. He suggests a drive around holiday with no particular plan to maximize the vacation vibes. Himachal Pradesh has left a similar mark. As for upcoming holidays, вҖң<em>We usually plan our long trip. It is usually well researched. We like to soak up the local culture, local cuisine, read about the people and try to pick up couple of words to converse in local dialect. People debate about whether the destination is more fun or the process of planning is? I say both are important. Even more important is the company that you have!вҖқ</em></p>\r\n\r\n<p><strong>How good are you with planning such outings? Or are you more likely to give the job to a professional? </strong></p>\r\n\r\n<p>All our trips are have been planned and executed by us. Usually we divide entire researching and planning amongst ourselves. Then we discuss and take the common factors and execute it ourselves. This way we know what we want. We also leave enough room for unplanned, spur of the moment kind of things.</p>\r\n\r\n<p>A handy person to have in the kitchen who loves his cake and eating it and making it too, Sanjay loves any food made with care and love. Obviously Thai cuisine that he favours. Who can find fault with that.</p>\r\n\r\n<p><strong>What genre of books do you like and who is your fave author?</strong></p>\r\n\r\n<p>I am voracious reader -work related (investment), fiction and non-fiction. Topics fascinate me now-a-days is: Psychology of Investments and Behavioral Finance. These are topics which was not covered during my college days and I believe they play a very critical part in Investments. I believe Investments is Science and Art. Science part is demand-supply, pricing and number crunching. Art part is how you assimilate that information and assess how they would be interpreted by people at large.</p>\r\n\r\n<p><strong>You have been influenced by:</strong></p>\r\n\r\n<p>Two people who have truly inspired me and rounded my personality are Helen Keller and Mother Theresa. Despite all her handicaps, Helen Keller achieved many things which a normal person could not. It is the same in investments- you may not have all resources, but you can still excel through sheer dint of hard work and determination.</p>\r\n\r\n<p>Mother Theresa inspires me with her caring. The way she went about it doing good, ethically and built a legacy which continues after her also is truly outstanding. That is something that I would like to emulate, build a system that lasts.</p>\r\n\r\n<p><strong>A truly interesting nugget about the man!!! </strong></p>\r\n\r\n<p>Besides my first love of updating myself on investment world, I have started planting trees. Idea is not just to plant a sapling but to see it grow. So whatever it takes in terms of ensuring adequate nutrients, water and proper care. It has been 3 years now and in next couple of years it should have an impact on the local surrounding.</p>', 1, 1, 1, '2020-10-05 05:30:00', '2022-02-17 12:56:03', '2022-02-17 12:34:32'),
(5, 'Vihang Naik', 'vihang-naik', 3, 'Fund Manager - Equity Investments', 'L&T Investment Management Limited', 'Vihang is the consummate fund professional in youthful garb. In every conversation and discussion, he brings in a perspective that really gets the participants to think and participate. Armed with CFA and BMS qualifications, and with the support of his family members consisting of his parents, and his wife and a young son, he remains grounded and real.', '<p>Given to enjoying his Sundays with friends, a game of badminton and a book perhaps, he truly looks forward to his vacations and outings. A long one every year and a few short breaks in between, he is best suited for a вҖңwhere the heart leads, the road followsвҖқ kind of vacation where new experiences, people and food are the highlights. Most of these are вҖңoff the beaten track and self designedвҖқ. A partial book lover with a predictable bias towards Yuval Harari, Tinkle and Suppandi comics and musings of Charlie Munger provides the sustenance for the hunger of his grey cells. He would much rather eat than cook and that too East Asian street food, and watch Lin Dan in tournament playing a delectable game of badminton for it to qualify as a great day spent. Playing poker also figures as a pastime and helping around the house is an avoidable chore.</p>\r\n\r\n<p><strong>Q:: Were you always interested in fund management or did you have any other aspirations?</strong></p>\r\n\r\n<p>I always liked investing. Deferred gratification comes naturally to me and is quite indispensable in investing.</p>\r\n\r\n<p><strong>Experience etc. with past companies:</strong></p>\r\n\r\n<p><strong>Q:: Do share a bit about your journey to your current position?</strong></p>\r\n\r\n<p>I started my journey as a sell-side analyst tracking the technology sector. I joined L&amp;T Asset Management in 2012 after it acquired FidelityвҖҷs India business. It had been almost four years since the GFC and equities were not a particularly exciting asset class. Most people were excited about real estate back then as high inflation favored that asset class and people were sitting on huge gains. It was a time when small and midcaps were completely ignored and you could find good companies at single digit PEs. Market leaders in a sector traded at a fraction of their sales and nobody would look at them. We were lucky to invest in a few of those вҖҳmultibaggersвҖҷ and create good wealth for our unit holders over the next few years.</p>\r\n\r\n<p><strong>Q:: You are a young fund manager. And there are a lot of very young people who want to become fund managers. What would you advise them on their life goals?</strong></p>\r\n\r\n<p>Charlie Munger had once remarked, \"If Warren Buffett had gone into ballet, no one would have heard of himвҖқ. The two pieces of advice I can give young people are:</p>\r\n\r\n<p>1) Figure out your own aptitudes, and</p>\r\n\r\n<p>2) Play games where those aptitudes matter</p>\r\n\r\n<p>These are the simplest ways to enjoy the game and be good at it.</p>\r\n\r\n<p><strong>Q:: Honesty and success!!! Are these diametric opposites? How do you reconcile them in your life?</strong></p>\r\n\r\n<p>Over the long term, I believe honesty and success go hand in hand. Unless you are honest with yourself and others I donвҖҷt think you can have the credibility to be successful.</p>\r\n\r\n<p><strong>On the schemes and markets</strong></p>\r\n\r\n<p><strong>Q:: Going forward, are you more hopeful of better days or do you think there are blips in between? And what are the probable causes of the blips?</strong></p>\r\n\r\n<p>I am an optimist and always believe that there will be better days ahead. Markets, however, follow their own pattern of euphoria and depression. The last 13 months have seen Midcap indices rise continuously without a meaningful correction. I believe there are pockets of froth and there are pockets of opportunities. Past experiences have taught us that one can find multibaggers even while indices look expensive.</p>\r\n\r\n<p><strong>Q: What will be the economic path that we take as a population? Meaning if you were to paint a one yearвҖҷs picture of the path to normalcy, how will that play</strong></p>\r\n\r\n<p>Over the last year and a half, we have had a difficult situation that necessitated hard choices. We have seen two lockdowns in two years which could have second order effects especially at the bottom of the pyramid. However, history teaches us that human beings are extraordinarily resilient, so we will come out strongly.</p>\r\n\r\n<p>On the positive front, vaccinations picking up pace could slow down a third wave, if we have one. I am positive on the exports front with the PLI incentives and labor arbitrage, India could become a manufacturing hub for select goods.</p>\r\n\r\n<p><strong>Q: When you move from handling one scheme and then move to another, do you wear a different thinking cap or is the process the determinant?</strong></p>\r\n\r\n<p>We have tried to build a process driven organization. Every fund follows its own mandate and chooses the best stocks from our coverage universe which adhere to the fundвҖҷs mandate.</p>\r\n\r\n<p><strong>Q: You are the primary and co fund manager with a number of schemes. Which is the most interesting one and why?</strong></p>\r\n\r\n<p>We have a strategy of having a primary and co-fund manager for each of our schemes. Each of my schemes has a different mandate and hence has different portfolios. So that makes all the schemes interesting to me.</p>\r\n\r\n<p>One scheme I want to talk about is the L&amp;T Focused Equity Fund. The mandate is to hold less than 30 stocks and take a focused approach. We have chosen to differentiate this fund with its sector exposure. In a market where most of the top stocks today are banks, the fund has chosen not to have banking exposure. The core thesis is that after a prolonged period of market cap creation, every sector attracts excess competition which lowers the sectorвҖҷs future RoEs. The fund gives a good diversification option for investors to participate in a multicap fund which has differentiated positioning.</p>\r\n\r\n<p><strong>Disclaimer:</strong></p>\r\n\r\n<p><img alt=\"https://lh5.googleusercontent.com/QvsEvxoV8yIPo6zmnpjrKQUp-COV9c6tS9HoLiVueiTxNY3qK7KpcdsoTrKyGBZjzTmju6UOJY4zgzQGFWKb8dGR5_pWtQfe0Y-GTYU--_9tWQwrafaAxyrDrFb5MScvI2SwjN8\" src=\"https://lh5.googleusercontent.com/QvsEvxoV8yIPo6zmnpjrKQUp-COV9c6tS9HoLiVueiTxNY3qK7KpcdsoTrKyGBZjzTmju6UOJY4zgzQGFWKb8dGR5_pWtQfe0Y-GTYU--_9tWQwrafaAxyrDrFb5MScvI2SwjN8\" style=\"height:308px; width:316px\"></p>\r\n\r\n<p>Riskometer as on June 30, 2021</p>\r\n\r\n<p>*Investors should consult their financial advisers if in doubt about whether the product is suitable for them.</p>\r\n\r\n<p><strong>Disclaimer вҖ“</strong> The article (including market views expressed herein) is for general information only and does not have regard to specific investment objectives, financial situation and the particular needs of any specific person who may receive this information. The article provides general information and comparisons made (if any) are only for illustration purposes. Investments in mutual funds and secondary markets inherently involve risks and recipients should consult their legal, tax and financial advisors before investing. Recipients of this document should understand that statements made herein regarding future prospects may not be realized. Recipients should also understand that any reference to the indices/ sectors/ securities/ schemes etc. in the article is only for illustration purpose and are NOT stock recommendation(s) from the author or L&amp;T Investment Management Limited, the asset management company of L&amp;T Mutual Fund (вҖңthe FundвҖқ) or any of its associates. Any performance information shown refers to the past and should not be seen as an indication of future returns. The value of investments and any income from them can go down as well as up. The distribution of the article in certain jurisdictions may be restricted or totally prohibited and accordingly, persons who come into possession of the article are required to inform themselves about, and to observe, any such restrictions.</p>\r\n\r\n<p><em>Mutual Fund investments are subject to market risks, read all scheme related documents carefully.</em></p>', 1, 1, 1, '2021-08-05 05:30:00', '2022-02-17 12:54:26', '2022-02-17 12:34:32');
