INSERT INTO `mpx_fund_taxation` (`ft_id`, `title`, `description`, `file`, `c_order`, `status`, `created_id`, `updated_id`, `created_at`, `updated_at`, `migration_at`) VALUES
(1, 'Mutual Fund Taxation-2020', 'In Union Budget 2020, Finance Ministry changed the tax policy in dividends. In priorpolicy, fund houses are responsible to pay Dividend Distribution Tax or DDT. But nowinvestors need to pay taxes on the income from dividends. ', '20200722Mutual-Fund-Taxation.pdf', 0, 1, 1, 1, '2020-07-22 05:30:00', '2022-02-08 10:44:33', '2022-02-08 10:44:33');
