INSERT INTO `mpx_fund_watch` (`fw_id`, `title`, `description`, `file`, `c_order`, `status`, `created_id`, `updated_id`, `created_at`, `updated_at`, `migration_at`) VALUES
(1, 'AXIS BLUECHIP FUND', 'Axis Bluechip Fund commenced from January 2010 as Axis Equity Fund. Later on, the fund changed its name to Axis Bluechip Fund and its scheme orientation to a largely Large Cap oriented fund. There is no history of merger with any other scheme or amalgamation of any other scheme into it.', '20200730AXIS_BLUECHIP_FUND_PDF.pdf', 0, 1, 1, 1, '2020-07-01 05:30:00', '2022-02-04 12:33:28', '2022-02-04 12:33:28'),
(2, 'CANARA ROBECO BLUECHIP EQUITY FUND', 'Canara Robeco Bluechip Equity Fund commenced in August 2010. The main objective of this fund to provide capital appreciation by predominantly investing in Companies, having a large market capitalization.', '20200818PDF - Canara Robeco Bluechip Report compressed.pdf', 0, 1, 1, 1, '2020-08-18 05:30:00', '2022-02-04 12:33:28', '2022-02-04 12:33:28'),
(3, 'MIRAE ASSET EMERGING BLUECHIP FUND', 'Mirae Asset Emerging Bluechip Fund commenced from August 2010. The main objective of this fund to generate income and capital appreciation from a diversified portfolio predominantly investing in Indian equities and equity related securities of largecap and midcap companies at the time of investment.', '20201030PDF_Mirae Asset Emerging Bluechip final.pdf', 0, 1, 1, 1, '2020-10-30 05:30:00', '2022-02-04 12:33:28', '2022-02-04 12:33:28'),
(4, 'NIPPON INDIA 150 MIDCAP INDEX FUND', ' Nippon India Nifty Midcap 150 Index Fund is a fund which takes the strategy away from our thinking to simply being in tandem with the index. The midcap segment, consisting of the companies having market capitalization ranking from 101 to 250 is a very dynamic segment with companies changing position based on market capitalization and also moving in and out of the index.', '20210513cnv_Formatted Nippon India 150 Midcap Index Fund.pdf', 0, 1, 1, 1, '2021-05-13 05:30:00', '2022-02-04 12:33:28', '2022-02-04 12:33:28'),
(5, 'NIPPON INDIA SMALLCAP INDEX 250 FUND', 'Investing in the equity market is a lot like the voyage of discovery that Alice undertook. With patience and discipline it could be the wondrous garden that Alice saw but one has to pass through the door no bigger than a rat hole to really make it work. But the real decision making comes in if we have to choose where to put in the money. ', '20210605Formatted Nippon India Smallcap Index 250 Fund.pdf', 0, 1, 1, 1, '2021-06-05 05:30:00', '2022-02-04 12:33:28', '2022-02-04 12:33:28');
