DELIMITER $$
--
-- Procedures
--
DROP PROCEDURE IF EXISTS `active_aums`$$
CREATE DEFINER=`stm_user_lr`@`localhost` PROCEDURE `active_aums` ()  BEGIN
            SELECT t1.fund_id, t1.fund_name, t1.fund_code, t2.corpus_entry FROM mpx_fund_master AS t1 LEFT OUTER JOIN mpx_corpus_entry AS t2 ON t1.fund_code = t2.fund_code WHERE t1.fund_opened <= CURDATE() AND ( t2.corpus_entry IS NULL OR t2.entry_date = (SELECT option_value FROM mpx_options WHERE option_key='aum') ) ORDER BY t1.fund_name ASC;
            END$$

DROP PROCEDURE IF EXISTS `active_funds`$$
CREATE DEFINER=`stm_user_lr`@`localhost` PROCEDURE `active_funds` ()  BEGIN
            SELECT *, (SELECT ROUND(closing_nav,2) FROM mpx_fund_detail B WHERE A.fund_code = B.fund_code AND B.entry_date = (SELECT option_value FROM mpx_options WHERE option_key='nav') LIMIT 1) AS last_nav FROM (	
                SELECT mpx_fund_master.fund_id AS fund_id, mpx_fund_master.fund_code AS fund_code,
                mpx_fund_master.fund_name AS fund_name, mpx_fund_core.cor AS cor
                FROM (mpx_fund_master) LEFT OUTER JOIN mpx_fund_core ON mpx_fund_master.fund_id = mpx_fund_core.fund_id
                WHERE mpx_fund_master.fund_opened <= CURDATE() ORDER BY fund_name ASC) A;
            END$$

DROP PROCEDURE IF EXISTS `active_indices`$$
CREATE DEFINER=`stm_user_lr`@`localhost` PROCEDURE `active_indices` ()  BEGIN
            SELECT a.idc_id, a.name, a.corelation, b.closing_value FROM mpx_indices_master AS a LEFT OUTER JOIN mpx_indices_detail AS b ON a.corelation = b.name AND b.entry_date = (SELECT option_value FROM mpx_options WHERE option_key='idx') ORDER BY a.corelation ASC;
            END$$

DELIMITER ;

